-- 01-02 Search of Persons
INSERT INTO procedures
  (procedure_number, name, issue_date, status, replaces_date, chapter_id,
   rationale, supervision, procedure_info, governing_authority, associated_governance)
VALUES (
  '01-02',
  'Search of Persons',
  '2021-11-24',
  'Amended',
  '2021-04-29',
  (SELECT id FROM chapters WHERE title = 'Chapter 1 – Arrest & Release' LIMIT 1),
  'The right to search a person is of paramount importance to the safety of prisoners, members, and all other persons employed within the criminal justice system. It is critical that officers make a proper evaluation of the potential risks, ensure that the appropriate type of search is conducted, and that they are diligent while searching persons in custody.
In December 2001, the Supreme Court of Canada made a ruling in the case of R. v. Golden, which directly impacted on the search of person incident to arrest.
The lawful authority for searching a person comes from statute or common law. Officers conducting searches must be able to articulate their authority and grounds for doing so. Information has been included in this Procedure that will assist officers in properly assessing the appropriate type of search to be conducted, and identify some of the risks that must be addressed (see Appendix B). In the absence of clear direction in the form of legislation, the courts have expressed some concerns with “routine police department policy applicable to all arrestees”. As a result, although this Procedure outlines possible risk factors, and places an obligation on police officers to address them, the decision as to what type of search is appropriate must be assessed on a case–by–case basis.
The Toronto Police Service (Service) agrees with the courts that clear legislative prescription as to when and how strip searches should be conducted would be of assistance to the police and to the courts.',
  'Officer in Charge notification mandatory
− after conducting a search at the station
− regarding grounds and circumstances (Strip search)
− there are reasonable grounds to believe the person under arrest has secreted weapons or evidence in a body cavity',
  '[{"type":"paragraph","children":[{"type":"text","text":"Searches of persons shall be conducted keeping in mind that the safety of Service members, the person being searched, and the public are paramount. All searches of the person should be conducted thoroughly and in a methodical manner. Searches of the person shall not be conducted in an abusive fashion or be conducted to intimidate, ridicule or induce admissions. Regardless of what type of search is undertaken, the dignity and the privacy of a person must always be given consideration."}]},{"type":"paragraph","children":[{"type":"text","text":"All searches of the person shall be conducted by peace officers of the same gender unless circumstances make it impractical to do so, having regard to the immediate risk of injury, escape, or"}]},{"type":"paragraph","children":[{"type":"text","text":"the destruction of evidence. Consideration shall be given when dealing with trans and gender diverse"}]},{"type":"paragraph","children":[{"type":"text","text":"persons, wherever practicable (see Appendix C)."}]}]'::jsonb,
  '[{"type":"paragraph","children":[{"type":"text","text":"Constitution Act, Part I, Canadian Charter of Rights and Freedoms (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Controlled Drugs and Substances Act (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Criminal Code (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Accessibility for Ontarians with Disabilities Act (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Anti-Racism Act, 2017 (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Liquor Licence Act (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Ministry of Correctional Services Act (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Ontario Human Rights Code (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Police Services Act (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Police Services Act, O. Reg 3/99, Adequacy & Effectiveness of Police Services (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Provincial Statutes (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Common Law (incident to arrest) (Other)"}]},{"type":"paragraph","children":[{"type":"text","text":"Cloutier v. Langlois (Supreme Court of Canada) (1990) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. Flintoff (Ontario Court of Appeal) (1998) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. Coulter (Ontario Court of Justice) (2000) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. Golden (Supreme Court of Canada) (2001) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. Clarke, Heroux and Pilipa (Ontario Superior Court of Justice) (2003) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. MacDonald (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. Mann (Supreme Court of Canada) (2004) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R v. McGuffie (Ontario Court of Appeal) (2016) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. MacPherson (Ontario Native Council on Justice) (2018) (Relevant Case Law)"}]},{"type":"paragraph","children":[{"type":"text","text":"R. v. Tonkin (Ontario Superior Court of Justice) (2020) (Relevant Case Law)"}]}]'::jsonb,
  '[{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB LE-005 Arrests"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB LE-012 Search of Persons"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB Policy Accessibility Standards for Customer Service;"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB Policy Race-Based Data Collection, Analysis and Public Reporting"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB Policy Search and Detention of Trans Persons"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB Policy Search of Persons"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–01 Arrest"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–03 Persons in Custody"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 03–06 Guarding Persons in Hospital"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 04–09 American Sign Language and Language Interpreters"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 09–06 Property of Persons in Custody"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 12– 01 Confidential Crown Envelope"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 13–17 Notes and Reports"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 16–07 Collection, Analysis and Reporting of Race and Identity-Based Data"}]},{"type":"paragraph","children":[{"type":"text","text":"Police Review: Office of the Independent Police Review Director, Breaking the Golden Rule: A Review of Police Strip\nSearches in Ontario."}]},{"type":"paragraph","children":[{"type":"text","text":"Other: 1.9.2 Standards of Conduct - Respect for Gender Diversity and Trans-Inclusive Policing"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: eReports"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: Booking and Search Template"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: Body Cavity Search Template"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: Search in the Field Only Template"}]},{"type":"paragraph","children":[{"type":"text","text":"Notices for Booking Hall: TPS 970 Booking and Search Notice – Manner of Search Notice – Frisk Search"}]},{"type":"paragraph","children":[{"type":"text","text":"Notices for Booking Hall: TPS 971 Booking and Search Notice – Manner of Search Notice – Strip Search"}]},{"type":"paragraph","children":[{"type":"text","text":"Notices for Booking Hall: TPS 972 Booking and Search Notice – Privacy Shield Notice"}]},{"type":"paragraph","children":[{"type":"text","text":"Notices for Booking Hall: TPS 973 Booking and Search Notice – Consular Access Notice"}]},{"type":"paragraph","children":[{"type":"text","text":"Notices for Booking Hall: TPS 974 Booking and Search Notice – Audio Privacy Notice"}]},{"type":"paragraph","children":[{"type":"text","text":"Notices for Booking Hall: TPS 975 Booking and Search Notice – Deferred Call to Lawyer Notice"}]}]'::jsonb
);

-- 01-03 Persons in Custody
INSERT INTO procedures
  (procedure_number, name, issue_date, status, replaces_date, chapter_id,
   rationale, supervision, procedure_info, governing_authority, associated_governance)
VALUES (
  '01-03',
  'Persons in Custody',
  '2022-07-28',
  'Amended',
  '2021-04-29',
  (SELECT id FROM chapters WHERE title = 'Chapter 1 – Arrest & Release' LIMIT 1),
  'The Service has a responsibility to ensure the safety of all persons who come into police custody and the safety of Service members. To ensure a reasonable level of safety, this Procedure sets out the standards of care for the transportation, booking, lodging and monitoring of prisoners.',
  '• Officer in Charge notification mandatory:
− when transporting a prisoner who requires priority in booking
− when a person in custody requires medical attention
− upon arrival at a police station with a person in custody
− when entering or leaving a detention facility with a person in custody
− when receiving a person for lodging in police cells
− when in doubt regarding the contents of the medication container, or if the prisoner requests
medication in excess of the prescribed dosage, or if the prisoner exhibits signs of alcohol
or drug consumption
− if Booking Hall System (BHS) or Detention Area Monitoring System (DAMS) equipment
malfunctions',
  NULL,
  '[{"type":"paragraph","children":[{"type":"text","text":"Constitution Act, Part I, Canadian Charter of Rights and Freedoms (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Controlled Drugs and Substances Act; (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Criminal Code; (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Youth Criminal Justice Act. (Federal)"}]},{"type":"paragraph","children":[{"type":"text","text":"Accessibility for Ontarians with Disabilities Act (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Ontario Human Rights Code (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Provincial Offences Act (Provincial)"}]},{"type":"paragraph","children":[{"type":"text","text":"Police Services Act, O. Reg 3/99, Adequacy & Effectiveness of Police Services. (Provincial)"}]}]'::jsonb,
  '[{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB LE-005 Arrests"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB LE-016 Prisoner Care and Control"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB LE-033 Prisoner Transportation"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB Policy Accessibility Standards for Customer Service"}]},{"type":"paragraph","children":[{"type":"text","text":"TPSB Policies: TPSB Policy Search and Detention of Trans Persons (Appendix E)"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–01 Arrest"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–02 Search of Persons"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–02 Appendix B Risk Assessment – Level of Search"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–02 Appendix C Trans Persons"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–02 Appendix D Handling Items of Religious Significance"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 01–15 Bail Hearings and Detention Orders"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 03–05 Withdrawal Management Centres"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 03–06 Guarding Persons in Hospital"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 03–07 Meal Provision for Persons in Custody"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 04–13 Foreign Nationals"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 06–11 Licensed Premises"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 07–09 Breath Interview"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 08–07 Communicable Diseases"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 09–01 Property – General"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 09–06 Property of Persons in Custody"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 12–01 Confidential Crown Envelope"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 12–08 Disclosure, Duplication and Transcription"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 13–19 Breath Tests for Service Members"}]},{"type":"paragraph","children":[{"type":"text","text":"TPS Procedures: 15–02 Injury/Illness Reporting"}]},{"type":"paragraph","children":[{"type":"text","text":"Other: 1.9.2 Standards of Conduct - Respect for Gender Diversity and Trans-Inclusive Policing"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: eReports"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: Prisoner Transportation List"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: Property Forms Wizard"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 105 Injury/Illness Report"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 175 Booking Hall DVD Log"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 191 Videotaping Notice"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 192 Electronic Recording Transportation Log"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 227 Person/Vehicle for Investigation"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 300 Last Drink Booking Log"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 407 Property Claim Notice"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 606 Transcription Service Request"}]},{"type":"paragraph","children":[{"type":"text","text":"Forms: TPS 649 Internal Correspondence"}]},{"type":"paragraph","children"