-- 3. Sub-procedures
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Arrest Authority',
  '[{"type":"paragraph","children":[{"type":"text","text":"Section 494 of the Criminal Code (CC) provides authorities for arrest without warrant by any person."}]},{"type":"paragraph","children":[{"type":"text","text":"In addition to the authorities to arrest without warrant given to any person in s. 494 CC, a peace officer"}]},{"type":"paragraph","children":[{"type":"text","text":"is given additional authorities under ss. 495(1), 524(2), 525(6) and 31(1) CC. A peace officer may"}]},{"type":"paragraph","children":[{"type":"text","text":"arrest any person who"}]},{"type":"paragraph","children":[{"type":"text","text":"495(1) • has committed an indictable offence, or a person the officer believes on"}]},{"type":"paragraph","children":[{"type":"text","text":"reasonable grounds has committed or is about to commit an indictable offence"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the officer finds committing a criminal offence"}]},{"type":"list-item","children":[{"type":"text","text":"on reasonable grounds, the officer believes is wanted on a warrant of arrest or"}]}]},{"type":"paragraph","children":[{"type":"text","text":"committal, which is in force within the territorial jurisdiction where the person is"}]},{"type":"paragraph","children":[{"type":"text","text":"found, or"}]},{"type":"paragraph","children":[{"type":"text","text":"524(2) and 525(6) • has contravened or is about to contravene the terms of a criminal release"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"has committed an indictable offence while on release for a criminal offence"}]}]},{"type":"paragraph","children":[{"type":"text","text":"31(1) • is found committing or it is believed on reasonable grounds is about to commit"}]},{"type":"paragraph","children":[{"type":"text","text":"a breach of the peace"}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Continuation of Arrest',
  '[{"type":"paragraph","children":[{"type":"text","text":"A police officer shall not arrest a person without warrant for summary conviction, dual procedure or 553"}]},{"type":"paragraph","children":[{"type":"text","text":"indictable offences where there are reasonable grounds to believe the public interest has been satisfied"}]},{"type":"paragraph","children":[{"type":"text","text":"having regard to all the circumstances including the need to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"establish the identity of the person"}]},{"type":"list-item","children":[{"type":"text","text":"secure or preserve evidence"}]},{"type":"list-item","children":[{"type":"text","text":"prevent the continuation or repetition of an offence"}]},{"type":"list-item","children":[{"type":"text","text":"ensure that the accused will appear in court"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the safety and security of any victim or of witness to the offence."}]}]},{"type":"paragraph","children":[{"type":"text","text":"In circumstances where the public interest is satisfied, an offender must be released"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"unconditionally with no intent to proceed to court"}]},{"type":"list-item","children":[{"type":"text","text":"unconditionally with intent to seek a criminal summons, or"}]},{"type":"list-item","children":[{"type":"text","text":"by way of an Appearance Notice (Form 9)."}]}]},{"type":"paragraph","children":[{"type":"text","text":"A police officer may continue the arrest (summary, dual, indictable 553 offences) of a person where the"}]},{"type":"paragraph","children":[{"type":"text","text":"public interest is not satisfied or for any indictable offence other than dual procedure and 553 indictable"}]},{"type":"paragraph","children":[{"type":"text","text":"offences. The criteria for satisfying the ‘public interest’ are set out in s. 497 CC."}]},{"type":"paragraph","children":[{"type":"text","text":"In circumstances where a continued detention is justified, the arrested person must be taken before an"}]},{"type":"paragraph","children":[{"type":"text","text":"Officer in Charge."}]},{"type":"paragraph","children":[{"type":"text","text":" The lack of appropriate release documentation to be served at an arrest scene is"}]},{"type":"paragraph","children":[{"type":"text","text":"not a valid reason for the continuation of an arrest."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Provincial Offences',
  '[{"type":"paragraph","children":[{"type":"text","text":"A police officer may also arrest a person under other authorities found in individual Provincial Statutes"}]},{"type":"paragraph","children":[{"type":"text","text":"such as the Highway Traffic Act, the Liquor Licence Act, and the Trespass to Property Act. There is no"}]},{"type":"paragraph","children":[{"type":"text","text":"general arrest authority for contravention of a Provincial Statute, and reference must be made to"}]},{"type":"paragraph","children":[{"type":"text","text":"individual statutes for specific arrest authorities."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Arrest in a Dwelling-House (Feeney Warrants)',
  '[{"type":"paragraph","children":[{"type":"text","text":"As a general rule, police officers are required to obtain a warrant prior to entering a dwelling–house to"}]},{"type":"paragraph","children":[{"type":"text","text":"arrest a person."}]},{"type":"paragraph","children":[{"type":"text","text":"Entry to a dwelling–house to affect an arrest is prohibited unless"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the arrest warrant is endorsed with an authorization to enter under ss. 529(1) CC, or"}]},{"type":"list-item","children":[{"type":"text","text":"the arrest warrant is accompanied by a separate entry authorization warrant issued under s."}]}]},{"type":"paragraph","children":[{"type":"text","text":"529.1 CC, or"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when there are reasonable grounds to suspect that entry into the dwelling–house is necessary"}]}]},{"type":"paragraph","children":[{"type":"text","text":"to prevent imminent bodily harm or death to any person, or"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when there are reasonable grounds to believe that evidence relating to the commission of an"}]}]},{"type":"paragraph","children":[{"type":"text","text":"indictable offence is present in the dwelling–house and that entry into the dwelling–house is"}]},{"type":"paragraph","children":[{"type":"text","text":"necessary to prevent the imminent loss or imminent destruction of evidence, or"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"in circumstances of fresh pursuit."}]}]},{"type":"paragraph","children":[{"type":"text","text":"Prior to entering a dwelling–house to execute an arrest warrant, members shall, whenever possible,"}]},{"type":"paragraph","children":[{"type":"text","text":"obtain"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"an endorsement on the arrest warrant under ss. 529(1) CC, or"}]},{"type":"list-item","children":[{"type":"text","text":"an authorization warrant (Form 7.1) under s. 529.1 CC."}]}]},{"type":"paragraph","children":[{"type":"text","text":"The authorization to enter may include such restrictions and conditions as the issuing Justice believes"}]},{"type":"paragraph","children":[{"type":"text","text":"reasonable to place on the arrest process."}]},{"type":"paragraph","children":[{"type":"text","text":"In all cases, members shall ensure proper announcement is made prior to entry (identification, purpose"}]},{"type":"paragraph","children":[{"type":"text","text":"of entry, etc.) except"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"as provided on the warrant, or"}]},{"type":"list-item","children":[{"type":"text","text":"where there are reasonable grounds to believe that prior announcement of the entry would"}]},{"type":"list-item","children":[{"type":"text","text":"expose the officer or any other person to imminent bodily harm or death, or"}]}]},{"type":"paragraph","children":[{"type":"text","text":"result in the imminent loss or imminent destruction of evidence relating to the"}]},{"type":"paragraph","children":[{"type":"text","text":"commission of an indictable offence."}]},{"type":"paragraph","children":[{"type":"text","text":"result in the imminent loss or imminent destruction of evidence relating to the"}]},{"type":"paragraph","children":[{"type":"text","text":"commission of an indictable offence."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"result in the imminent loss or imminent destruction of evidence relating to the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"commission of an indictable offence."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Medical Considerations - Positional Asphyxia',
  '[{"type":"paragraph","children":[{"type":"text","text":"Members should be aware that certain restraint positions (i.e. stomach down) might compromise heart"}]},{"type":"paragraph","children":[{"type":"text","text":"and lung functions increasing the risk of death. Unless circumstances make it impossible, persons"}]},{"type":"paragraph","children":[{"type":"text","text":"should be restrained in a sitting position while being closely watched. Use of the sitting position permits"}]},{"type":"paragraph","children":[{"type":"text","text":"easier breathing and cardiac function while affording good positional control over the individual."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Medical Considerations - Excited Delirium',
  '[{"type":"paragraph","children":[{"type":"text","text":"Excited delirium is a condition that can be caused by drug or alcohol intoxication, psychiatric illness or"}]},{"type":"paragraph","children":[{"type":"text","text":"a combination of both. Symptoms displayed by persons suffering from the condition may include any"}]},{"type":"paragraph","children":[{"type":"text","text":"combination of"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"abnormal tolerance to pain"}]},{"type":"list-item","children":[{"type":"text","text":"abnormal tolerance to pepper spray"}]},{"type":"list-item","children":[{"type":"text","text":"acute onset of paranoia"}]},{"type":"list-item","children":[{"type":"text","text":"bizarre or aggressive behaviour"}]},{"type":"list-item","children":[{"type":"text","text":"disorientation"}]},{"type":"list-item","children":[{"type":"text","text":"hallucinations"}]},{"type":"list-item","children":[{"type":"text","text":"impaired thinking"}]},{"type":"list-item","children":[{"type":"text","text":"panic"}]},{"type":"list-item","children":[{"type":"text","text":"shouting"}]},{"type":"list-item","children":[{"type":"text","text":"sudden calm after frenzied activity"}]},{"type":"list-item","children":[{"type":"text","text":"sweating, fever, heat intolerance"}]},{"type":"list-item","children":[{"type":"text","text":"unexpected physical strength"}]},{"type":"list-item","children":[{"type":"text","text":"violence towards others."}]}]},{"type":"paragraph","children":[{"type":"text","text":"Due to their inclination to violence and extreme exertion, persons exhibiting the symptoms of excited"}]},{"type":"paragraph","children":[{"type":"text","text":"delirium are often restrained for their own protection and the protection of others. Members should be"}]},{"type":"paragraph","children":[{"type":"text","text":"cognizant of positional asphyxia when dealing with persons exhibiting the symptoms of excited delirium"}]},{"type":"paragraph","children":[{"type":"text","text":"and, unless circumstances make it impossible, restrain the person in a sitting position as noted above."}]},{"type":"paragraph","children":[{"type":"text","text":"Persons exhibiting the symptoms of excited delirium must always be treated as suffering from a medical"}]},{"type":"paragraph","children":[{"type":"text","text":"emergency and once secured, be transported to hospital for examination."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Race and Identity-Based Data Collection',
  '[{"type":"paragraph","children":[{"type":"text","text":"As outlined in Procedure 16–07, the Toronto Police Services Board Policy entitled “Race-Based Data"}]},{"type":"paragraph","children":[{"type":"text","text":"Collection, Analysis and Public Reporting” requires the Toronto Police Service (Service) to collect,"}]},{"type":"paragraph","children":[{"type":"text","text":"analyze and publicly report on data related to the race of those individuals with whom Service members"}]},{"type":"paragraph","children":[{"type":"text","text":"interact."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Self-Identified Trans or Gender Diverse Persons',
  '[{"type":"paragraph","children":[{"type":"text","text":"Section 1 of the Ontario Human Rights Code states “Every person has a right to equal treatment with"}]},{"type":"paragraph","children":[{"type":"text","text":"respect to services, goods and facilities, without discrimination because of race, ancestry, place of"}]},{"type":"paragraph","children":[{"type":"text","text":"origin, colour, ethnic origin, citizenship, creed, sex, sexual orientation, gender identity, gender"}]},{"type":"paragraph","children":[{"type":"text","text":"expression, age, marital status, family status or disability.”"}]},{"type":"paragraph","children":[{"type":"text","text":"The Service acknowledges its obligation and responsibility, short of undue hardship, to accommodate"}]},{"type":"paragraph","children":[{"type":"text","text":"self-identified trans or gender diverse persons. Members conducting searches of self-identified trans"}]},{"type":"paragraph","children":[{"type":"text","text":"or gender diverse persons shall comply with Appendix C by"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"referring to the person in their chosen name and gender pronoun(s)"}]},{"type":"list-item","children":[{"type":"text","text":"after discussion with the prisoner, lodge according to their self-identified gender or lodging"}]}]},{"type":"paragraph","children":[{"type":"text","text":"preference in accordance with 01-03 Appendix E unless it can be proven that there are specific"}]},{"type":"paragraph","children":[{"type":"text","text":"overriding health and safety concerns that cannot be resolved, rendering the accommodation"}]},{"type":"paragraph","children":[{"type":"text","text":"impossible. When a prisoner cannot be accommodated in this regard, members shall clearly"}]},{"type":"paragraph","children":[{"type":"text","text":"articulate the reasons in their memorandum book; and"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure that information regarding a trans prisoner’s gender identity or gender history is shared on"}]}]},{"type":"paragraph","children":[{"type":"text","text":"a need-to-know basis only with those persons directly involved with the case"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"explain to the individual the following 3 options for a Search"}]},{"type":"list-item","children":[{"type":"text","text":"conducted by officers who are men only or"}]},{"type":"list-item","children":[{"type":"text","text":"conducted by officers who are women only or"}]},{"type":"list-item","children":[{"type":"text","text":"a split search"}]},{"type":"list-item","children":[{"type":"text","text":"the Officer in Charge shall be guided by the preference of the individual to be searched in terms"}]}]},{"type":"paragraph","children":[{"type":"text","text":"of the gender of the person conducting the search"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when required to remove a gender-affirming article or prosthetic device/item (including breast"}]}]},{"type":"paragraph","children":[{"type":"text","text":"forms, chest binders, gaffs, packers, prosthetic penises and wigs) from a trans, gender diverse or"}]},{"type":"paragraph","children":[{"type":"text","text":"cis-gendered person shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"advise the person of the reason for removing the device/item"}]},{"type":"list-item","children":[{"type":"text","text":"provide the person with the opportunity to remove the device/item themselves when self-"}]}]},{"type":"paragraph","children":[{"type":"text","text":"removal does not pose potential risk of safety/injury to the person or member"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"be cognizant that trans and gender diverse persons may have an emotional as well as physical"}]}]},{"type":"paragraph","children":[{"type":"text","text":"attachment to their gender affirming items and shall treat the device/items with respect at all"}]},{"type":"paragraph","children":[{"type":"text","text":"times"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"in the case of prosthetic devices"}]},{"type":"list-item","children":[{"type":"text","text":"whenever practicable allow for the removal of the device in a private area"}]},{"type":"list-item","children":[{"type":"text","text":"when self-removal is not possible, ask the person how to properly remove the device"}]},{"type":"list-item","children":[{"type":"text","text":"allow adequate space and range of motion for reattachment of the device"}]},{"type":"list-item","children":[{"type":"text","text":"return the device/item to the person as soon as possible upon completion of the search"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the retention of gender-affirming personal articles including"}]},{"type":"paragraph","children":[{"type":"text","text":"gender-affirming prosthetics shall be made on a case by case basis complying with"}]},{"type":"paragraph","children":[{"type":"text","text":"1.9.2 Standards of Conduct considering all risk factors, including those contained in"}]},{"type":"paragraph","children":[{"type":"text","text":"Appendix B, Appendix C and 01-03 Appendix E. All available accommodation"}]},{"type":"paragraph","children":[{"type":"text","text":"options shall be considered when making an assessment."}]},{"type":"paragraph","children":[{"type":"text","text":" When it is determined that a person cannot be accommodated, the reasons for the"}]},{"type":"paragraph","children":[{"type":"text","text":"determination must be clearly articulated in the memorandum book including all"}]},{"type":"paragraph","children":[{"type":"text","text":"accommodation options considered."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"make appropriate entries in the memorandum book, including the Booking and Search Template option"}]}]},{"type":"paragraph","children":[{"type":"text","text":"selected by the person, and the rationale for the course of action taken"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"complete the appropriate sections of the Booking and Search Template."}]}]},{"type":"paragraph","children":[{"type":"text","text":" Members shall document why particular actions were or were not taken."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Items of Religious Significance',
  '[{"type":"paragraph","children":[{"type":"text","text":"Section 2 of the Canadian Charter of Rights and Freedoms (Charter) gives everyone the fundamental"}]},{"type":"paragraph","children":[{"type":"text","text":"“freedom of conscience and religion”. Section 8 of the Charter states that “everyone has the right to be"}]},{"type":"paragraph","children":[{"type":"text","text":"secure against unreasonable search or seizure”."}]},{"type":"paragraph","children":[{"type":"text","text":"Section 1 of the Ontario Human Rights Code states “Every person has a right to equal treatment with"}]},{"type":"paragraph","children":[{"type":"text","text":"respect to services, goods and facilities, without discrimination because of race, ancestry, place of"}]},{"type":"paragraph","children":[{"type":"text","text":"origin, colour, ethnic origin, citizenship, creed, sex, sexual orientation, gender identity, gender"}]},{"type":"paragraph","children":[{"type":"text","text":"expression, age, marital status, family status or disability.” From this section, creed is the issue that"}]},{"type":"paragraph","children":[{"type":"text","text":"deals with religious beliefs."}]},{"type":"paragraph","children":[{"type":"text","text":"The Service recognizes that special arrangements may have to be made when handling items, articles,"}]},{"type":"paragraph","children":[{"type":"text","text":"apparel, or clothing a person identifies as having religious importance (item of religious significance)."}]},{"type":"paragraph","children":[{"type":"text","text":"Members conducting searches of persons shall treat an item of religious significance with respect and"}]},{"type":"paragraph","children":[{"type":"text","text":"handle the item appropriately."}]},{"type":"paragraph","children":[{"type":"text","text":"Although there are a multitude of items of religious significance that differ between and amongst"}]},{"type":"paragraph","children":[{"type":"text","text":"religions, any item of religious significance identified by a person shall be handled according to the"}]},{"type":"paragraph","children":[{"type":"text","text":"process established in Appendix D, unless circumstances make it impractical to do so, having regard"}]},{"type":"paragraph","children":[{"type":"text","text":"for the"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"immediate risk of injury"}]},{"type":"list-item","children":[{"type":"text","text":"immediate risk of escape"}]},{"type":"list-item","children":[{"type":"text","text":"immediate risk of destruction of evidence"}]},{"type":"list-item","children":[{"type":"text","text":"safety of the member"}]},{"type":"list-item","children":[{"type":"text","text":"safety of the person"}]},{"type":"list-item","children":[{"type":"text","text":"safety of the public"}]}]},{"type":"paragraph","children":[{"type":"text","text":"The member must be able to articulate why particular actions were or were not taken."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Duty to Accommodate Persons with Disabilities',
  '[{"type":"paragraph","children":[{"type":"text","text":"The Service has a duty to accommodate persons with disabilities under the Ontario Human Rights"}]},{"type":"paragraph","children":[{"type":"text","text":"Code and the Accessibility for Ontarians with Disabilities Act. When required, any infringement of a"}]},{"type":"paragraph","children":[{"type":"text","text":"person’s right to be accommodated must be minimal in nature, and no more than is necessary to"}]},{"type":"paragraph","children":[{"type":"text","text":"achieve the desired objective."}]},{"type":"paragraph","children":[{"type":"text","text":"Therefore, when it is deemed necessary to remove an assistive device from a person with a disability"}]},{"type":"paragraph","children":[{"type":"text","text":"to conduct a search, the device should be returned to the person as soon as practicable upon"}]},{"type":"paragraph","children":[{"type":"text","text":"completion of the search."}]},{"type":"paragraph","children":[{"type":"text","text":"Assessments regarding the retention of assistive devices shall be made on a case-by-case basis taking"}]},{"type":"paragraph","children":[{"type":"text","text":"into consideration all risk factors, including those contained in Appendix B. Members shall also consider"}]},{"type":"paragraph","children":[{"type":"text","text":"all available accommodation options when making their assessment."}]},{"type":"paragraph","children":[{"type":"text","text":"When it is determined that a person cannot be accommodated, members must clearly articulate the"}]},{"type":"paragraph","children":[{"type":"text","text":"reasons for the determination in their memorandum book including all accommodation options"}]},{"type":"paragraph","children":[{"type":"text","text":"considered."}]},{"type":"paragraph","children":[{"type":"text","text":"Members shall be cognizant that persons requiring the aid of an assistive device may have an emotional"}]},{"type":"paragraph","children":[{"type":"text","text":"as well as physical attachment to the device and shall treat the assistive device with respect at all times."}]},{"type":"paragraph","children":[{"type":"text","text":"When considering the continued detention of an arrested person who is accompanied by a guide dog"}]},{"type":"paragraph","children":[{"type":"text","text":"due to blindness, visual impairment, hearing impairment, or other physical disability, members shall"}]},{"type":"paragraph","children":[{"type":"text","text":"make reasonable effort to have the guide dog accommodated by friends or relatives or call the Toronto"}]},{"type":"paragraph","children":[{"type":"text","text":"Police Operations Centre for further resources such as Canine Vision Canada or the Humane Society."}]},{"type":"paragraph","children":[{"type":"text","text":"Guide dogs shall not be transported to court with a prisoner."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Grounds for Searching a Person',
  '[{"type":"paragraph","children":[{"type":"text","text":"For a search to be lawful it must be reasonable and justified given all the circumstances and it must be"}]},{"type":"paragraph","children":[{"type":"text","text":"conducted for a valid reason. The onus is on the officers conducting and authorizing a search to"}]},{"type":"paragraph","children":[{"type":"text","text":"demonstrate that the search is justified in law, necessary and reasonable."}]},{"type":"paragraph","children":[{"type":"text","text":"Warrantless searches are prima facie unreasonable and contrary to s. 8 of the Charter. However,"}]},{"type":"paragraph","children":[{"type":"text","text":"searches incident to the arrest of a person are recognized as lawful at common law and do not require"}]},{"type":"paragraph","children":[{"type":"text","text":"a warrant. Searches cannot be justified by citing standard procedures. However, for safety reasons,"}]},{"type":"paragraph","children":[{"type":"text","text":"except in extenuating circumstances, all persons under arrest must be searched at the first available"}]},{"type":"paragraph","children":[{"type":"text","text":"opportunity."}]},{"type":"paragraph","children":[{"type":"text","text":"Stronger grounds are required as the level of intrusiveness of a search increases. A Protective search"}]},{"type":"paragraph","children":[{"type":"text","text":"and Frisk search must be completed prior to any Strip search being conducted. The searching officer"}]},{"type":"paragraph","children":[{"type":"text","text":"must obtain authorization from the Officer in Charge to determine if there is reasonable and probable"}]},{"type":"paragraph","children":[{"type":"text","text":"grounds to authorize a Strip search. The more intrusive the search the more justification is required,"}]},{"type":"paragraph","children":[{"type":"text","text":"and officers must be able to articulate the need for the more intrusive search (see Appendix B)."}]},{"type":"paragraph","children":[{"type":"text","text":" Strip searches shall not be conducted on persons brought into custody by Toronto"}]},{"type":"paragraph","children":[{"type":"text","text":"Police officers based solely on the grounds that the person may come into contact"}]},{"type":"paragraph","children":[{"type":"text","text":"with other persons in custody. Accordingly, persons in custody who have been"}]},{"type":"paragraph","children":[{"type":"text","text":"Frisk searched are no longer restricted from being placed with those who have been"}]},{"type":"paragraph","children":[{"type":"text","text":"Strip searched."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Search Authorities',
  '[{"type":"paragraph","children":[{"type":"text","text":"A police officer may search a person"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"with a person’s consent"}]},{"type":"list-item","children":[{"type":"text","text":"when authorized by statute"}]},{"type":"list-item","children":[{"type":"text","text":"after an arrest has been made (common law – incident to an arrest)"}]}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Consent Search',
  '[{"type":"paragraph","children":[{"type":"text","text":"Consent search generally applies to persons who are not under arrest. A police officer must be able to"}]},{"type":"paragraph","children":[{"type":"text","text":"demonstrate that consent for a search was informed and freely given. A person giving consent for a"}]},{"type":"paragraph","children":[{"type":"text","text":"search must understand the possible consequences of the search prior to giving consent. A Consent"}]},{"type":"paragraph","children":[{"type":"text","text":"search, in most instances, should not be used where other lawful authority exists."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Search Authorized by Statute',
  '[{"type":"paragraph","children":[{"type":"text","text":"Specific statutes contain search provisions that can be used when circumstances warrant. The related"}]},{"type":"paragraph","children":[{"type":"text","text":"statute should be referred to prior to conducting such searches; for example: the Criminal Code, the"}]},{"type":"paragraph","children":[{"type":"text","text":"Controlled Drugs and Substances Act, and the Liquor Licence Act."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Search Incident to Arrest',
  '[{"type":"paragraph","children":[{"type":"text","text":"The right to search as an incident to a lawful arrest is found in common law, and has been upheld by"}]},{"type":"paragraph","children":[{"type":"text","text":"the Supreme Court, as long as the search is conducted for a valid objective and is not conducted in an"}]},{"type":"paragraph","children":[{"type":"text","text":"abusive fashion. (Cloutier v. Langlois, 1990)"}]},{"type":"paragraph","children":[{"type":"text","text":"As an incident to arrest a police officer may search for"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"weapons"}]},{"type":"list-item","children":[{"type":"text","text":"anything that could cause injury (including drugs and alcohol)"}]},{"type":"list-item","children":[{"type":"text","text":"anything that could assist in a person’s escape"}]},{"type":"list-item","children":[{"type":"text","text":"evidence"}]}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Recording Searches',
  '[{"type":"paragraph","children":[{"type":"text","text":"Wherever practicable, all Protective and Frisk searches including the removal of excess clothing must"}]},{"type":"paragraph","children":[{"type":"text","text":"be captured on audio and video."}]},{"type":"paragraph","children":[{"type":"text","text":"Full details of all searches shall be recorded in the memorandum book including the grounds for the"}]},{"type":"paragraph","children":[{"type":"text","text":"type of search conducted. Appropriate entries shall be recorded in the applicable eReport for all Strip"}]},{"type":"paragraph","children":[{"type":"text","text":"and Body Cavity searches and must be completed in its entirety."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Race and Identity-Based Data Collection',
  '[{"type":"paragraph","children":[{"type":"text","text":"As outlined in Procedure 16–07, the Toronto Police Services Board Policy entitled “Race-Based Data"}]},{"type":"paragraph","children":[{"type":"text","text":"Collection, Analysis and Public Reporting” requires the Toronto Police Service (Service) to collect,"}]},{"type":"paragraph","children":[{"type":"text","text":"analyze and publicly report on data related to the race of those individuals with whom Service members"}]},{"type":"paragraph","children":[{"type":"text","text":"interact."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Court Officers/Custodial Officers',
  '[{"type":"paragraph","children":[{"type":"text","text":"Court Officers/Custodial Officers may search persons in accordance with this Procedure in conjunction"}]},{"type":"paragraph","children":[{"type":"text","text":"with unit-specific policies."}]},{"type":"paragraph","children":[{"type":"text","text":"Member"}]},{"type":"paragraph","children":[{"type":"text","text":"1. When conducting a search shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"record all Protective and Frisk searches on audio and video, and if not able to do so, record"}]}]},{"type":"paragraph","children":[{"type":"text","text":"reasons in the memorandum book"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"not use any more force than is necessary and reasonable under the circumstances to"}]}]},{"type":"paragraph","children":[{"type":"text","text":"conduct a search"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"make every effort to provide persons who do not speak English or who by reason of disability"}]}]},{"type":"paragraph","children":[{"type":"text","text":"have difficulty communicating"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"with the services of an interpreter in compliance with Procedure 04–09, or"}]},{"type":"list-item","children":[{"type":"text","text":"other person who can assist the person in understanding the process"}]},{"type":"list-item","children":[{"type":"text","text":"advise the person of the reason that they are being searched"}]},{"type":"list-item","children":[{"type":"text","text":"search the person"}]},{"type":"list-item","children":[{"type":"text","text":"every effort should be made, where appropriate, to have the searching officers be of the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"same gender as the person being searched and comply with Appendix C when searching"}]},{"type":"paragraph","children":[{"type":"text","text":"a trans person"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"search the area within the person''s immediate surroundings, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"remove weapons, anything that could cause injury (including drugs and alcohol), anything"}]}]},{"type":"paragraph","children":[{"type":"text","text":"that could assist in the person''s escape, or evidence of an offence, as applicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"seize all evidence obtained"}]},{"type":"list-item","children":[{"type":"text","text":"ask the person if they have an item of religious significance on their person or in their"}]}]},{"type":"paragraph","children":[{"type":"text","text":"possession, and comply with Appendix D, when applicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when required to remove an item of religious significance make reasonable effort to ensure"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the removal and search occurs in a private setting"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when practicable, facilitate the replacement of an item as soon as possible when an item of"}]}]},{"type":"paragraph","children":[{"type":"text","text":"religious significance (apparel or clothing only) is removed and held for any purpose and is"}]},{"type":"paragraph","children":[{"type":"text","text":"not being immediately returned to that person"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when required to remove an assistive device from a person with a disability or a gender-"}]}]},{"type":"paragraph","children":[{"type":"text","text":"affirming prosthetic from a trans or gender diverse person (see Appendix C)"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"advise the person of the reason for removing the device/item"}]},{"type":"list-item","children":[{"type":"text","text":"provide the person with the opportunity to remove the device/item themselves when self-"}]}]},{"type":"paragraph","children":[{"type":"text","text":"removal does not pose potential risk of safety/injury to the person or member"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"treat the assistive device/item with respect at all times"}]},{"type":"list-item","children":[{"type":"text","text":"in the case of prosthetic devices"}]},{"type":"list-item","children":[{"type":"text","text":"whenever practicable allow for the removal of the device in a private area"}]},{"type":"list-item","children":[{"type":"text","text":"when self-removal is not possible, ask the person how to properly remove the device"}]},{"type":"list-item","children":[{"type":"text","text":"allow adequate space and range of motion for reattachment of the device"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Prosthetic devices are attached to the body; therefore, improper removal can injure"}]},{"type":"paragraph","children":[{"type":"text","text":"the person and/or damage the device."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"return the device/item to the person as soon as possible upon completion of the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"search"}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the retention of assistive devices shall be made on a case-"}]},{"type":"paragraph","children":[{"type":"text","text":"by-case basis taking into consideration all risk factors, including those contained in"}]},{"type":"paragraph","children":[{"type":"text","text":"Appendix B. All available accommodation options shall also be considered when"}]},{"type":"paragraph","children":[{"type":"text","text":"making an assessment."}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the retention of gender-affirming personal articles including"}]},{"type":"paragraph","children":[{"type":"text","text":"gender-affirming prosthetics shall be made on a case by case basis complying with"}]},{"type":"paragraph","children":[{"type":"text","text":"1.9.2 Standards of Conduct considering all risk factors, including those contained in"}]},{"type":"paragraph","children":[{"type":"text","text":"Appendix B, Appendix C and 01-03 Appendix E. All available accommodation"}]},{"type":"paragraph","children":[{"type":"text","text":"options shall be considered when making an assessment."}]},{"type":"paragraph","children":[{"type":"text","text":" When it is determined that a person cannot be accommodated, the reasons for the"}]},{"type":"paragraph","children":[{"type":"text","text":"determination must be clearly articulated in the memorandum book including all"}]},{"type":"paragraph","children":[{"type":"text","text":"accommodation options considered."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"record all relevant details in the memorandum book"}]}]},{"type":"paragraph","children":[{"type":"text","text":"2. When a search of person has occurred in the field and the person has not been booked into a"}]},{"type":"paragraph","children":[{"type":"text","text":"police facility shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"complete the Search in the Field Only Template"}]}]},{"type":"paragraph","children":[{"type":"text","text":"3. When conducting a consent search of a person shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ask for the consent of the person and explain the nature of the search"}]},{"type":"list-item","children":[{"type":"text","text":"inform the person that they have a right to refuse consent"}]},{"type":"list-item","children":[{"type":"text","text":"inform the person of potential consequences of the search, including the possibility that"}]}]},{"type":"paragraph","children":[{"type":"text","text":"anything seized may be used as evidence"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"immediately stop searching the person if consent is withdrawn, unless evidence has been"}]}]},{"type":"paragraph","children":[{"type":"text","text":"disclosed that would permit continuation pursuant to lawful authorities"}]},{"type":"paragraph","children":[{"type":"text","text":"4. Prior to transporting an arrested person shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"search the police vehicle prior to placing the arrested person in the vehicle"}]},{"type":"list-item","children":[{"type":"text","text":"for reasons of safety, ensure the arrested person has been searched except where the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"search would interfere with the administration of emergency medical assistance"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"every effort should be made, where appropriate, to have the searching officers be of the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"same gender as the person being searched and comply with Appendix C when searching"}]},{"type":"paragraph","children":[{"type":"text","text":"a trans person"}]},{"type":"paragraph","children":[{"type":"text","text":"5. After arrival at the station with an arrested person shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"search the police vehicle"}]},{"type":"list-item","children":[{"type":"text","text":"advise the Officer in Charge what type of search has been conducted and what has been"}]}]},{"type":"paragraph","children":[{"type":"text","text":"found thus far"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"if a Frisk search has not been fully completed then ensure the Frisk search is completed in its"}]}]},{"type":"paragraph","children":[{"type":"text","text":"entirety in front of the Officer in Charge and is audio and video recorded"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the manner of Booking and Search Notice - Frisk Search is read to the person prior to"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the search"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when it is believed that reasonable grounds exist for a Strip search, articulate to the Officer in"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Charge and advise them of the grounds and circumstances involved"}]},{"type":"paragraph","children":[{"type":"text","text":"6. When reasonable and probable grounds have been satisfied and a Strip search is deemed"}]},{"type":"paragraph","children":[{"type":"text","text":"necessary by the Officer in Charge, the searching officers shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"read the arrested party their rights to counsel prior to the Strip search being conducted and"}]}]},{"type":"paragraph","children":[{"type":"text","text":"ensure they are provided a reasonable opportunity to speak to counsel before the search"}]},{"type":"paragraph","children":[{"type":"text","text":"commences"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"advise the Officer in Charge if the person identifies that they have an item of religious"}]}]},{"type":"paragraph","children":[{"type":"text","text":"significance on their person or in their possession"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"search the person in a private area and ensure the search is audiotaped (if applicable), but"}]}]},{"type":"paragraph","children":[{"type":"text","text":"not videotaped"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"be of the same gender as the person being searched, except in exigent circumstances"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Appendix C when searching trans persons"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the number of police officers involved in the search are no more than is reasonably"}]}]},{"type":"paragraph","children":[{"type":"text","text":"necessary in the circumstances"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"where appropriate,"}]},{"type":"list-item","children":[{"type":"text","text":"ask the person to remove clothing one article at a time,"}]},{"type":"list-item","children":[{"type":"text","text":"document whether the arrested person removed items of clothing themselves, and"}]},{"type":"list-item","children":[{"type":"text","text":"record all relevant details in the memorandum book and the Booking and Search Template"}]},{"type":"list-item","children":[{"type":"text","text":"not remove of any more articles of clothing than necessary"}]},{"type":"list-item","children":[{"type":"text","text":"not seize bras, underwire bras and string bikini tops unless there is reasonable grounds to"}]}]},{"type":"paragraph","children":[{"type":"text","text":"believe it is necessary to do so"}]},{"type":"paragraph","children":[{"type":"text","text":" This action can amount to an unlawful Strip search."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"not perform any more visual inspection of the person’s body than is necessary to achieve the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"objectives of the search"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"inspect each article of clothing in a methodical manner"}]},{"type":"list-item","children":[{"type":"text","text":"permit the person to replace articles of clothing after inspection, where appropriate"}]},{"type":"list-item","children":[{"type":"text","text":"provide replacement clothing for articles seized as evidence as soon as possible"}]},{"type":"list-item","children":[{"type":"text","text":"not leave the person in a completely naked state after the search"}]}]},{"type":"paragraph","children":[{"type":"text","text":"7. When a Strip search has been completed shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the Officer in Charge will complete the Booking and Search Template"}]},{"type":"list-item","children":[{"type":"text","text":"if applicable, the Officer in Charge will complete the Trans Person Specific Details section of"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the Booking and Search Template"}]},{"type":"paragraph","children":[{"type":"text","text":" Members shall not conduct Strip searches in any location other than a private"}]},{"type":"paragraph","children":[{"type":"text","text":"area of a secure police facility, unless there is an immediate safety risk where no"}]},{"type":"paragraph","children":[{"type":"text","text":"other option is available. Members shall advise a supervisor prior to commencing"}]},{"type":"paragraph","children":[{"type":"text","text":"the search, if unsafe, then at the earliest opportunity. Members shall provide the"}]},{"type":"paragraph","children":[{"type":"text","text":"person the highest degree of privacy possible given the circumstances. Upon"}]},{"type":"paragraph","children":[{"type":"text","text":"completion, members will report to the Officer in Charge the circumstances. The"}]},{"type":"paragraph","children":[{"type":"text","text":"Officer in Charge shall complete a “Strip Search – Not in a Police Facility”"}]},{"type":"paragraph","children":[{"type":"text","text":"occurrence and notify the Unit Commander."}]},{"type":"paragraph","children":[{"type":"text","text":"Police Officer"}]},{"type":"paragraph","children":[{"type":"text","text":"8. Where there are reasonable grounds to believe that a person under arrest has secreted weapons"}]},{"type":"paragraph","children":[{"type":"text","text":"or evidence in a body cavity shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"consult with the Officer in Charge"}]},{"type":"list-item","children":[{"type":"text","text":"escort the person to the hospital"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 03–06"}]},{"type":"list-item","children":[{"type":"text","text":"request that the person remove the item in a controlled area of the hospital and with a"}]}]},{"type":"paragraph","children":[{"type":"text","text":"medical professional present, if possible"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"if the person is unable or unwilling to remove the item and consents to a search"}]},{"type":"list-item","children":[{"type":"text","text":"ensure that the search is conducted by a qualified medical practitioner"}]},{"type":"list-item","children":[{"type":"text","text":"remain with the person while the search is taking place (same gender officers only, or if"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the person has self-identified as trans or gender diverse, in compliance with Appendix C)"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"advise the Officer in Charge of the results"}]},{"type":"list-item","children":[{"type":"text","text":"where the person refuses a Body Cavity search by a medical practitioner, and the item has"}]}]},{"type":"paragraph","children":[{"type":"text","text":"not been removed"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"advise the Officer in Charge"}]},{"type":"list-item","children":[{"type":"text","text":"restrain the person and hold in isolation pending a Show Cause Hearing"}]},{"type":"list-item","children":[{"type":"text","text":"continuously monitor the person to ensure their safety and the safety of Service members"}]}]},{"type":"paragraph","children":[{"type":"text","text":"until recovery of the item or substance is made"}]},{"type":"paragraph","children":[{"type":"text","text":"9. When a Body Cavity search has been completed shall complete a Body Cavity Search Template"}]},{"type":"paragraph","children":[{"type":"text","text":"in compliance with item 7."}]},{"type":"paragraph","children":[{"type":"text","text":"Officer in Charge"}]},{"type":"paragraph","children":[{"type":"text","text":"10. An Officer in Charge of a unit where persons are detained shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the decision to search a person has been evaluated based on reasonable and probable"}]}]},{"type":"paragraph","children":[{"type":"text","text":"grounds and all risk factors, including those found in Appendix B"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"all arrested parties are advised, on camera, of the level of search to be performed and the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"manner and location in which it will be carried out"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"a Frisk search must be completed prior to any Strip search being conducted"}]},{"type":"list-item","children":[{"type":"text","text":"when applicable, all Frisk searches must be audio and video recorded. If not, the reason"}]}]},{"type":"paragraph","children":[{"type":"text","text":"shall be documented accordingly"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"searches are conducted appropriately and the required Booking and Search Template has"}]}]},{"type":"paragraph","children":[{"type":"text","text":"been completed for all booked prisoners.• every effort is made to provide persons who do not speak English or, who by reason of"}]},{"type":"paragraph","children":[{"type":"text","text":"disability have difficulty communicating"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"with the services of an interpreter in compliance with Procedure 04–09, or"}]},{"type":"list-item","children":[{"type":"text","text":"other person who can assist the person in understanding the process"}]},{"type":"list-item","children":[{"type":"text","text":"prisoners’ property is handled in compliance Procedures 01–03 and 09–06, as applicable"}]},{"type":"list-item","children":[{"type":"text","text":"when an item of religious significance is removed from a person that the item is treated with"}]}]},{"type":"paragraph","children":[{"type":"text","text":"respect and handled appropriately in compliance with Appendix D"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"assessments regarding the retention of assistive devices are made on a case-by-case basis"}]}]},{"type":"paragraph","children":[{"type":"text","text":"taking into consideration all risk factors, including those contained in Appendix B, and all"}]},{"type":"paragraph","children":[{"type":"text","text":"available accommodation options"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when it is determined that a person with a disability requiring the aid of an assistive device"}]}]},{"type":"paragraph","children":[{"type":"text","text":"cannot be accommodated, the reasons for the determination are clearly articulated in the"}]},{"type":"paragraph","children":[{"type":"text","text":"memorandum book, including all accommodation options considered"}]},{"type":"paragraph","children":[{"type":"text","text":"The Officer in Charge can authorize the use of an approved Handheld Metal Detector to assist in the"}]},{"type":"paragraph","children":[{"type":"text","text":"search of any prisoner at any point of the booking and search process, or at any point while the person"}]},{"type":"paragraph","children":[{"type":"text","text":"is lodged in the station. For a search to be lawful, using the Handheld Metal Detector, it must be"}]},{"type":"paragraph","children":[{"type":"text","text":"reasonable and justified given all the circumstances and it must be conducted for a valid reason."}]},{"type":"paragraph","children":[{"type":"text","text":" Hand Held Metal Detectors are only for use inside a police facility"}]},{"type":"paragraph","children":[{"type":"text","text":" Where a Handheld Metal Detector has been used the appropriate entries shall be"}]},{"type":"paragraph","children":[{"type":"text","text":"made in the Booking and Search Template"}]},{"type":"paragraph","children":[{"type":"text","text":" Staff Sergeants shall book prisoners and authorize Strip searches, unless at a"}]},{"type":"paragraph","children":[{"type":"text","text":"Central lock-up where a designate can be appointed"}]},{"type":"paragraph","children":[{"type":"text","text":"11. Upon being consulted regarding a Strip search shall determine whether the search is appropriate,"}]},{"type":"paragraph","children":[{"type":"text","text":"based on the information provided by the parading officer and the circumstances involved; and"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"where reasonable grounds to conduct a Strip search exist, shall"}]},{"type":"list-item","children":[{"type":"text","text":"advise the arrested party of the authorization to conduct a Strip search"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the manner of Booking and Search Notice - Strip Search is read to the person"}]}]},{"type":"paragraph","children":[{"type":"text","text":"prior to the search"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the arrested party is re-read their rights to counsel prior to the Strip search"}]}]},{"type":"paragraph","children":[{"type":"text","text":"beingconducted and ensure they are provided a reasonable opportunity to speak to"}]},{"type":"paragraph","children":[{"type":"text","text":"counsel before the search commences"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"provide the arrested party the opportunity to speak to counsel prior to the Strip search"}]}]},{"type":"paragraph","children":[{"type":"text","text":"commencing"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"read the Audio Privacy notice prior to the phone call to counsel"}]},{"type":"list-item","children":[{"type":"text","text":"escort to use the phone, give audio privacy, but maintain visual for safety"}]},{"type":"list-item","children":[{"type":"text","text":"in rare circumstances, where the Officer in Charge believes that there are safety concerns"}]}]},{"type":"paragraph","children":[{"type":"text","text":"that would prohibit the officer from allowing the arrested party access to counsel prior to"}]},{"type":"paragraph","children":[{"type":"text","text":"the Strip search, shall explain on video to the arrested party and note the reason in the"}]},{"type":"paragraph","children":[{"type":"text","text":"memorandum book."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the Deferred Call to Counsel Notice be read by the Officer in Charge and noted in"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the Booking and Search Template, if required"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"where reasonable grounds do not exist, ensure a Strip search is not conducted"}]}]},{"type":"paragraph","children":[{"type":"text","text":"12. Upon being consulted regarding a Body Cavity search shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"determine whether the search is appropriate, given the circumstances"}]},{"type":"list-item","children":[{"type":"text","text":"ensure that transporting and relieving officers accompanying an accused for the purpose of a"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Body Cavity Search are the same gender unless the person has self-identified as a trans"}]},{"type":"paragraph","children":[{"type":"text","text":"person and requests otherwise Appendix C"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the search is conducted by a qualified medical practitioner at a medical facility"}]},{"type":"list-item","children":[{"type":"text","text":"ensure a Body Cavity Search Template is completed"}]}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45323' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'General',
  '[{"type":"paragraph","children":[{"type":"text","text":"Audio/video equipment has been installed in central lock–ups and booking halls"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"to monitor and record the condition of persons in police custody and Service members"}]},{"type":"list-item","children":[{"type":"text","text":"to ensure their safety"}]},{"type":"list-item","children":[{"type":"text","text":"for court purposes."}]}]},{"type":"paragraph","children":[{"type":"text","text":"Under no circumstances shall a member obstruct the view of the camera while it is recording, or tamper"}]},{"type":"paragraph","children":[{"type":"text","text":"with any video storage media."}]},{"type":"paragraph","children":[{"type":"text","text":"Members shall comply with Procedure 12–08 when accessing, storing, viewing or duplicating any"}]},{"type":"paragraph","children":[{"type":"text","text":"electronically recorded material. A member shall never apply a police seal or other similar device to"}]},{"type":"paragraph","children":[{"type":"text","text":"any videotape, DVD/CD and/or the associated storage case."}]},{"type":"paragraph","children":[{"type":"text","text":"Interview rooms are not to be used as police cells. They shall be used only for the processing and"}]},{"type":"paragraph","children":[{"type":"text","text":"interviewing of prisoners, victims or witnesses. The Officer in Charge shall ensure that applicable"}]},{"type":"paragraph","children":[{"type":"text","text":"sections of this Procedure relating to the care and handling of persons in custody is applied to all"}]},{"type":"paragraph","children":[{"type":"text","text":"persons while detained in the police facility regardless of location (e.g. police cells, interview rooms)."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '01-03' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Accused Young Persons',
  '[{"type":"paragraph","children":[{"type":"text","text":"A young person under 18 years of age may be lodged in a divisional cell only"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"to prevent injury or to protect others from aggressive behaviour AND"}]},{"type":"list-item","children":[{"type":"text","text":"when there is no adult present in the cells, OR"}]},{"type":"list-item","children":[{"type":"text","text":"when there is an adult present in the cells and there is adequate space to isolate the young"}]}]},{"type":"paragraph","children":[{"type":"text","text":"person from the adult."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '01-03' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Prisoner’s Property',
  '[{"type":"paragraph","children":[{"type":"text","text":"In order to maximize the safety of prisoners held in police custody and the Service members assigned"}]},{"type":"paragraph","children":[{"type":"text","text":"to their care, it is the practice of the Toronto Police Service that the following property be removed from"}]},{"type":"paragraph","children":[{"type":"text","text":"every prisoner"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"valuable property"}]},{"type":"list-item","children":[{"type":"text","text":"evidence"}]},{"type":"list-item","children":[{"type":"text","text":"implements of escape"}]},{"type":"list-item","children":[{"type":"text","text":"offensive weapons as defined in the Criminal Code"}]},{"type":"list-item","children":[{"type":"text","text":"items which could be used as a ligature including belts, ties, and shoelaces"}]},{"type":"list-item","children":[{"type":"text","text":"items which could be used to cause damage to property including matches, lighters, combs,"}]}]},{"type":"paragraph","children":[{"type":"text","text":"keys and other sharp objects"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"prescription and over the counter medications"}]},{"type":"list-item","children":[{"type":"text","text":"tobacco products"}]}]},{"type":"paragraph","children":[{"type":"text","text":" With respect to assistive/prosthetic devices, comply with the Duty to Accommodate"}]},{"type":"paragraph","children":[{"type":"text","text":"sections below."}]},{"type":"paragraph","children":[{"type":"text","text":"When handling an item of religious significance the item shall be treated with respect and handled"}]},{"type":"paragraph","children":[{"type":"text","text":"appropriately in compliance with Procedure 01–02 Appendix D. The decision to permit the retention of"}]},{"type":"paragraph","children":[{"type":"text","text":"religious or personal items rests with the Officer in Charge based on an evaluation of the associated"}]},{"type":"paragraph","children":[{"type":"text","text":"safety risks."}]},{"type":"paragraph","children":[{"type":"text","text":"Persons released from custody shall have their property inventoried on camera as it is returned to"}]},{"type":"paragraph","children":[{"type":"text","text":"them."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '01-03' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Duty to Accommodate Persons with Disabilities',
  '[{"type":"paragraph","children":[{"type":"text","text":"The Service has a duty to accommodate persons with disabilities under the Ontario Human Rights"}]},{"type":"paragraph","children":[{"type":"text","text":"Code and the Accessibility for Ontarians with Disabilities Act. Therefore, persons with a disability"}]},{"type":"paragraph","children":[{"type":"text","text":"requiring the aid of an assistive device should be permitted to keep their device while in custody."}]},{"type":"paragraph","children":[{"type":"text","text":"When required, any infringement of a person’s right to be accommodated must be minimal in nature,"}]},{"type":"paragraph","children":[{"type":"text","text":"and no more than is necessary to achieve the desired objective. Assessments regarding the removal"}]},{"type":"paragraph","children":[{"type":"text","text":"of an assistive device shall be made on a case-by-case basis. When making an assessment,"}]},{"type":"paragraph","children":[{"type":"text","text":"members shall take into consideration all risk factors, including those contained in Procedure 01–02"}]},{"type":"paragraph","children":[{"type":"text","text":"Appendix B. Members shall also consider all available accommodation options when making their"}]},{"type":"paragraph","children":[{"type":"text","text":"assessment (e.g. placing the person in a cell by themselves)."}]},{"type":"paragraph","children":[{"type":"text","text":"The determination regarding the removal of a person’s assistive device while they are in custody shall"}]},{"type":"paragraph","children":[{"type":"text","text":"be reassessed should circumstances regarding their custody change."}]},{"type":"paragraph","children":[{"type":"text","text":"Members must be mindful at all times of their legislative duty to accommodate persons with"}]},{"type":"paragraph","children":[{"type":"text","text":"disabilities. When it is determined that a person with a disability cannot be accommodated while in"}]},{"type":"paragraph","children":[{"type":"text","text":"custody, members must clearly articulate the reasons for the determination in their memorandum book"}]},{"type":"paragraph","children":[{"type":"text","text":"including all accommodation options considered."}]},{"type":"paragraph","children":[{"type":"text","text":"Members should be cognizant that persons requiring the aid of an assistive device may have an"}]},{"type":"paragraph","children":[{"type":"text","text":"emotional as well as physical attachment to the device and shall treat assistive devices with respect at"}]},{"type":"paragraph","children":[{"type":"text","text":"all times."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '01-03' LIMIT 1)
);
INSERT INTO sub_procedures (name, description, procedure_id) VALUES (
  'Duty to Accommodate Gender Identity and Gender Expression',
  '[{"type":"paragraph","children":[{"type":"text","text":"Section 1 of the Ontario Human Rights Code states “Every person has a right to equal treatment with"}]},{"type":"paragraph","children":[{"type":"text","text":"respect to services, goods and facilities, without discrimination because of race, ancestry, place of"}]},{"type":"paragraph","children":[{"type":"text","text":"origin, colour, ethnic origin, citizenship, creed, sex, sexual orientation, gender identity, gender"}]},{"type":"paragraph","children":[{"type":"text","text":"expression, age, marital status, family status or disability.”"}]},{"type":"paragraph","children":[{"type":"text","text":"The Service acknowledges its obligation and responsibility, short of undue hardship, to accommodate"}]},{"type":"paragraph","children":[{"type":"text","text":"self-identified trans or gender diverse persons. Members must be mindful when handling personal items"}]},{"type":"paragraph","children":[{"type":"text","text":"of trans or gender diverse persons such as but not limited to, clothing, makeup, and other items that"}]},{"type":"paragraph","children":[{"type":"text","text":"express/affirm gender identity, including prosthetic devices. These personal items shall be treated with"}]},{"type":"paragraph","children":[{"type":"text","text":"respect and handled appropriately in compliance with 1.9.2 Standards of Conduct and Procedure 01-02"}]},{"type":"paragraph","children":[{"type":"text","text":"Appendix C and Appendix E of this procedure. The decision to permit the retention or prosthetic devices"}]},{"type":"paragraph","children":[{"type":"text","text":"and other personal items that support their gender identity and expression rests with the Officer in"}]},{"type":"paragraph","children":[{"type":"text","text":"Charge and will be to the point of undue hardship."}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the retention of gender-affirming personal articles including"}]},{"type":"paragraph","children":[{"type":"text","text":"gender-affirming prosthetics shall be made on a case by case basis complying with"}]},{"type":"paragraph","children":[{"type":"text","text":"1.9.2 Standards of Conduct considering all risk factors, including those contained in"}]},{"type":"paragraph","children":[{"type":"text","text":"01-02 Appendix B, 01-02 Appendix C and Appendix E. All available accommodation"}]},{"type":"paragraph","children":[{"type":"text","text":"options shall be considered when making an assessment."}]},{"type":"paragraph","children":[{"type":"text","text":"Member – Court Services"}]},{"type":"paragraph","children":[{"type":"text","text":"1. In addition to the applicable items in this Procedure and its Appendices, Court Services personnel"}]},{"type":"paragraph","children":[{"type":"text","text":"shall comply with the unit–specific policies relating to the care, handling and transportation of"}]},{"type":"paragraph","children":[{"type":"text","text":"prisoners in Court Cells."}]},{"type":"paragraph","children":[{"type":"text","text":"Member"}]},{"type":"paragraph","children":[{"type":"text","text":"2. When transporting a person in custody shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"using only those handcuffs, leg irons and other restraining devices authorized by the Chief of"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Police, place the person in handcuffs using the approved manner and utilize the double–lock"}]},{"type":"paragraph","children":[{"type":"text","text":"mechanism where possible in order to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"prevent the escape of a person in custody"}]},{"type":"list-item","children":[{"type":"text","text":"control the violent activities of a person in custody"}]},{"type":"list-item","children":[{"type":"text","text":"when handcuffs are not used, be prepared to justify this decision"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Keeping in mind officer and public safety, officers may use discretion when"}]},{"type":"paragraph","children":[{"type":"text","text":"determining whether to handcuff an individual as it may not be practical or"}]},{"type":"paragraph","children":[{"type":"text","text":"necessary in all circumstances (e.g. due to a person’s medical condition, age,"}]},{"type":"paragraph","children":[{"type":"text","text":"disability, pregnancy, or frailty)."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"not leave the prisoner unattended"}]},{"type":"list-item","children":[{"type":"text","text":"place the person in the rear of the police vehicle"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Where the police vehicle has no screen, the person shall be placed in the right rear"}]},{"type":"paragraph","children":[{"type":"text","text":"seat. If an escort is available, the escort shall occupy the left rear seat."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"allow one (1) prisoner per vehicle (wagons excepted), when possible, comply with Appendix"}]}]},{"type":"paragraph","children":[{"type":"text","text":"E when transporting trans person"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"permit only those police officers involved in the investigation inside the vehicle with an"}]}]},{"type":"paragraph","children":[{"type":"text","text":"arrested person"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure prisoners and civilians (e.g. witnesses) are not transported in the same police vehicle"}]},{"type":"list-item","children":[{"type":"text","text":"prior to departure, advise the communications operator of the destination, the gender identity"}]}]},{"type":"paragraph","children":[{"type":"text","text":"and age of the person, and the odometer reading"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"advise the communications operator of the odometer reading upon arrival"}]}]},{"type":"paragraph","children":[{"type":"text","text":"3. When requested by another member to transport a person in custody to a police station shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"record the following information in the memorandum book"}]},{"type":"list-item","children":[{"type":"text","text":"arresting officer’s name"}]},{"type":"list-item","children":[{"type":"text","text":"reason for the arrest and continued detention"}]},{"type":"list-item","children":[{"type":"text","text":"requesting member''s name, badge number, rank and unit"}]},{"type":"list-item","children":[{"type":"text","text":"person''s name and charge"}]},{"type":"list-item","children":[{"type":"text","text":"any other pertinent information relating to the person or to the arrest"}]},{"type":"list-item","children":[{"type":"text","text":"provide the requesting member with their name, rank, badge number and unit"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Police Officer"}]},{"type":"paragraph","children":[{"type":"text","text":"4. When a non–violent person is taken into custody for being intoxicated shall process the person in"}]},{"type":"paragraph","children":[{"type":"text","text":"compliance with Procedure 03–05, whenever possible."}]},{"type":"paragraph","children":[{"type":"text","text":"5. When transporting a prisoner who, due to their mental, physical or emotional condition, requires"}]},{"type":"paragraph","children":[{"type":"text","text":"priority in booking and processing to decrease the likelihood of a confrontation, health or safety"}]},{"type":"paragraph","children":[{"type":"text","text":"risk shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"request the communications operator to notify the Officer in Charge of the station to which"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the prisoner is being transported"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"attend the station and book the prisoner as soon as practicable"}]}]},{"type":"paragraph","children":[{"type":"text","text":"6. When a person in custody requires medical attention due to illness, injury or intoxication shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"if necessary, and if qualified in standard first aid and CPR, perform first aid and/or CPR on"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the person, as required"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"transport the person to the nearest hospital if safe to do so, or request the attendance of"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Toronto Paramedic Services (Paramedics)"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"notify the Officer in Charge"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 03–06, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 06–11, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 15–02, if applicable"}]}]},{"type":"paragraph","children":[{"type":"text","text":"7. Upon arrival at a police station with a person in custody shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"request entry"}]},{"type":"list-item","children":[{"type":"text","text":"escort the person into the facility"}]},{"type":"list-item","children":[{"type":"text","text":"read the posted TPS 191 to the person while the BHS is recording"}]},{"type":"list-item","children":[{"type":"text","text":"take the person before the Officer in Charge"}]},{"type":"list-item","children":[{"type":"text","text":"advise the Officer in Charge of"}]},{"type":"list-item","children":[{"type":"text","text":"the reasons for the arrest"}]},{"type":"list-item","children":[{"type":"text","text":"the reasons for continued detention"}]},{"type":"list-item","children":[{"type":"text","text":"any other pertinent information relating to the person or to the arrest including, but not"}]}]},{"type":"paragraph","children":[{"type":"text","text":"limited to"}]},{"type":"paragraph","children":[{"type":"text","text":"i. known or suspected suicidal tendencies"}]},{"type":"paragraph","children":[{"type":"text","text":"ii. violent tendencies"}]},{"type":"paragraph","children":[{"type":"text","text":"iii. serious medical conditions"}]},{"type":"paragraph","children":[{"type":"text","text":"iv. assistive devices"}]},{"type":"paragraph","children":[{"type":"text","text":"v. safety concerns"}]},{"type":"paragraph","children":[{"type":"text","text":"vi. injuries"}]},{"type":"paragraph","children":[{"type":"text","text":"vii. emotional disturbance, any known mental illness or developmental disability"}]},{"type":"paragraph","children":[{"type":"text","text":"viii. medication, or whether any medication has been administered"}]},{"type":"paragraph","children":[{"type":"text","text":"ix. impairment due to alcohol or drugs"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"comply with the Procedure 01–02"}]},{"type":"list-item","children":[{"type":"text","text":"to ensure the safety of the person and to prevent injury or escape, remove and secure"}]}]},{"type":"paragraph","children":[{"type":"text","text":"personal property from the prisoner in compliance with Procedures 01–02, 09–01 and 09–06"}]},{"type":"paragraph","children":[{"type":"text","text":"8. Prior to lodging a person in police cells shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"take the person before the Officer in Charge and advise of any pertinent information relating"}]}]},{"type":"paragraph","children":[{"type":"text","text":"to the person or to the arrest including, but not limited to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"known or suspected suicidal tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"violent tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"serious medical conditions"}]},{"type":"list-item","children":[{"type":"text","text":"assistive devices"}]},{"type":"list-item","children":[{"type":"text","text":"safety concerns"}]},{"type":"list-item","children":[{"type":"text","text":"injuries"}]},{"type":"list-item","children":[{"type":"text","text":"emotional disturbance, any known mental illness or developmental disability"}]},{"type":"list-item","children":[{"type":"text","text":"medication, or whether any medication has been administered"}]},{"type":"list-item","children":[{"type":"text","text":"impairment due to alcohol or drugs"}]}]},{"type":"paragraph","children":[{"type":"text","text":"9. When leaving or returning to a detention facility with a person in custody shall advise the Officer"}]},{"type":"paragraph","children":[{"type":"text","text":"in Charge and enter and exit only via the booking hall."}]},{"type":"paragraph","children":[{"type":"text","text":"10. Where a person in custody exhibits violent behaviour, or threatens or attempts suicide, and it is"}]},{"type":"paragraph","children":[{"type":"text","text":"believed that the person''s Master Name Index (MNI) and Criminal Numerical Index (CNI) file should"}]},{"type":"paragraph","children":[{"type":"text","text":"include a \"caution flag\" shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"add the information to the Remarks field in the person’s MNI"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Records Management Services – Operations (RMS–Ops) will receive and add the"}]},{"type":"paragraph","children":[{"type":"text","text":"applicable information to CPIC."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"submit a TPS 227, if applicable"}]}]},{"type":"paragraph","children":[{"type":"text","text":"11. Where a person in custody has provided a false name or identification shall update the"}]},{"type":"paragraph","children":[{"type":"text","text":"information in the MNI and all other relevant records as soon as possible."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"where the chosen name of a trans person aligns with their gender and lived identity but does"}]}]},{"type":"paragraph","children":[{"type":"text","text":"not match their identification documents shall ensure the person’s chosen name and pronoun"}]},{"type":"paragraph","children":[{"type":"text","text":"are consistently used in compliance with Procedure 01-02 Appendix C"}]},{"type":"paragraph","children":[{"type":"text","text":"Booking Officer"}]},{"type":"paragraph","children":[{"type":"text","text":"12. The booking officer shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"be responsible for the booking, lodging and safekeeping of prisoners"}]},{"type":"list-item","children":[{"type":"text","text":"ensure that the booking/release process is recorded in compliance with Appendix D"}]},{"type":"list-item","children":[{"type":"text","text":"make the appropriate entries on the TPS 175 for each recording"}]},{"type":"list-item","children":[{"type":"text","text":"make the appropriate entries on the TPS 300 for each booking process, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"forward the completed TPS 300 to the Detective Sergeant, at 2400 hours each day or as"}]}]},{"type":"paragraph","children":[{"type":"text","text":"close as practicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"make the appropriate entries in the Arrest Booking/Cell Management screen in relation to"}]},{"type":"list-item","children":[{"type":"text","text":"booking"}]},{"type":"list-item","children":[{"type":"text","text":"detention"}]},{"type":"list-item","children":[{"type":"text","text":"all prisoner movements"}]},{"type":"list-item","children":[{"type":"text","text":"phone calls and feedings"}]},{"type":"list-item","children":[{"type":"text","text":"property"}]},{"type":"list-item","children":[{"type":"text","text":"medication"}]},{"type":"list-item","children":[{"type":"text","text":"release"}]}]},{"type":"paragraph","children":[{"type":"text","text":" It is crucial that prisoner movement in and out of the cells be recorded in the Arrest"}]},{"type":"paragraph","children":[{"type":"text","text":"Booking/Cell Management screen. In the event that an incident occurs in the cells,"}]},{"type":"paragraph","children":[{"type":"text","text":"Property and Video Evidence Management Unit (PVEMU) will rely on this"}]},{"type":"paragraph","children":[{"type":"text","text":"information to locate the relevant recordings."}]},{"type":"paragraph","children":[{"type":"text","text":"13. Upon entry of an arrested person into the facility shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"activate the BHS and record the following"}]},{"type":"list-item","children":[{"type":"text","text":"the escorting officer reading the TPS 191"}]},{"type":"list-item","children":[{"type":"text","text":"the complete booking of the person, excluding telephone calls and Level 3 searches"}]},{"type":"list-item","children":[{"type":"text","text":"the removal and inventory of property"}]},{"type":"list-item","children":[{"type":"text","text":"the release of the person"}]},{"type":"list-item","children":[{"type":"text","text":"all entries and exits of the person leaving and returning to the facility."}]}]},{"type":"paragraph","children":[{"type":"text","text":" All activity in the cell area including the complete lodging of the prisoner will be"}]},{"type":"paragraph","children":[{"type":"text","text":"recorded on the DAMS."}]},{"type":"paragraph","children":[{"type":"text","text":"14. When receiving a person for lodging in police cells shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"notify the Officer in Charge"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 01–02"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Appendix A"}]},{"type":"list-item","children":[{"type":"text","text":"treat items of religious significance with respect and handle in compliance with Procedure"}]}]},{"type":"paragraph","children":[{"type":"text","text":"01–02, Appendix D"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"treat trans persons with respect and handle any gender-affirming personal items including"}]}]},{"type":"paragraph","children":[{"type":"text","text":"gender-affirming prosthetics in compliance with 01-02 Appendix C and Appendix E to the point"}]},{"type":"paragraph","children":[{"type":"text","text":"of undue hardship"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"secure the person in a cell"}]},{"type":"list-item","children":[{"type":"text","text":"segregate female prisoners from male prisoners when it is necessary to place them in police"}]}]},{"type":"paragraph","children":[{"type":"text","text":"cells, or ensure they are transported to the female lock–up at 55 Division"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"segregate accused young persons from adult prisoners when it is necessary to detain them in"}]}]},{"type":"paragraph","children":[{"type":"text","text":"a divisional cell pending release or transport to a young persons’ lock–up"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"store the property bag and other personal effects in a secure area as designated by the Unit"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Commander"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"not store property bags and other personal effects in the corridor opposite the prisoner’s cell"}]},{"type":"list-item","children":[{"type":"text","text":"make the appropriate entries in the Arrest Booking/Cell Management screen"}]}]},{"type":"paragraph","children":[{"type":"text","text":"15. When a person in custody has a disability requiring the aid of an assistive device"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"shall assess whether to permit the person to keep their assistive device by"}]},{"type":"list-item","children":[{"type":"text","text":"considering all risk factors, including those contained in Procedure 01–02 Appendix B"}]},{"type":"list-item","children":[{"type":"text","text":"considering all available accommodation options, such as placing the person in a"}]}]},{"type":"paragraph","children":[{"type":"text","text":"segregated cell"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"should permit the person to keep their device while in custody, if possible"}]},{"type":"list-item","children":[{"type":"text","text":"shall consult with the Officer in Charge if unable to permit the accommodation"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the removal of an assistive device shall be made on a case-"}]},{"type":"paragraph","children":[{"type":"text","text":"by-case basis."}]},{"type":"paragraph","children":[{"type":"text","text":"16. When a person in custody is accompanied by a guide dog shall comply with Procedure 01–01."}]},{"type":"paragraph","children":[{"type":"text","text":"17. When a person in custody has soiled their clothing with bodily fluids (e.g. vomit, urine) shall"}]},{"type":"paragraph","children":[{"type":"text","text":"arrange for replacement clothing as soon as possible."}]},{"type":"paragraph","children":[{"type":"text","text":"18. When there are persons lodged in the police cells shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"physically attend the cells to check the condition of persons detained in custody and"}]},{"type":"list-item","children":[{"type":"text","text":"use a target of 30 minutes between physical cell checks having regard for all the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"circumstances during the tour of duty"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"record the checks in the Cell Check screen as directed in Appendix B"}]},{"type":"list-item","children":[{"type":"text","text":"notify the Officer in Charge of any change in condition of persons in custody"}]},{"type":"list-item","children":[{"type":"text","text":"notify the Officer in Charge immediately when it is necessary to reassess a person’s"}]}]},{"type":"paragraph","children":[{"type":"text","text":"assistive device accommodation due to a change in circumstances"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"awaken intoxicated persons a minimum of every 4 hours but more frequently if circumstances"}]}]},{"type":"paragraph","children":[{"type":"text","text":"require"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"provide food in compliance with Procedure 03–07"}]},{"type":"list-item","children":[{"type":"text","text":"make the appropriate entries in the Arrest Booking/Cell Management screen"}]},{"type":"list-item","children":[{"type":"text","text":"print the Prisoner Transportation Report prior to transport"}]}]},{"type":"paragraph","children":[{"type":"text","text":"19. Once a cell that has been used to lodge a person is vacated shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"inspect the cell for any property and/or contraband as soon as practicable but in any event"}]}]},{"type":"paragraph","children":[{"type":"text","text":"prior to any other individual being lodged in that cell"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"deal with any items found in compliance with Procedures 09–01 and 09–06"}]}]},{"type":"paragraph","children":[{"type":"text","text":"20. When receiving a request for access to prescribed medication from a person in custody shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"inspect the medication container and ensure"}]},{"type":"list-item","children":[{"type":"text","text":"compliance with Appendix A"}]},{"type":"list-item","children":[{"type":"text","text":"the patient''s name on the medication container label matches the person"}]},{"type":"list-item","children":[{"type":"text","text":"if there is a discrepancy, call the pharmacy and ask whether they accept the legal name"}]}]},{"type":"paragraph","children":[{"type":"text","text":"or chosen name when filling prescriptions for gender diverse or trans persons"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"there is only one type of pill in the medication container"}]},{"type":"list-item","children":[{"type":"text","text":"the container label and contents do not appear to have been tampered with"}]},{"type":"list-item","children":[{"type":"text","text":"the medication container label is legible"}]},{"type":"list-item","children":[{"type":"text","text":"the expiry date on the medication container label has not passed, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the medication is dispensed in accordance with the directions and warning labels on"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the medication container label"}]},{"type":"paragraph","children":[{"type":"text","text":"21. When complying with a request for prescribed medication shall record each access on the"}]},{"type":"paragraph","children":[{"type":"text","text":"Administer screen."}]},{"type":"paragraph","children":[{"type":"text","text":"22. When in doubt regarding the contents of the medication container, or if the prisoner requests"}]},{"type":"paragraph","children":[{"type":"text","text":"medication in excess of the prescribed dosage, or if the prisoner exhibits signs of alcohol or drug"}]},{"type":"paragraph","children":[{"type":"text","text":"consumption shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"notify the Officer in Charge"}]},{"type":"list-item","children":[{"type":"text","text":"consult with the prescribing physician or another physician at a medical facility"}]}]},{"type":"paragraph","children":[{"type":"text","text":"23. If the BHS or DAMS equipment malfunctions shall immediately notify the Officer in Charge and"}]},{"type":"paragraph","children":[{"type":"text","text":"make the appropriate entry on the TPS 175."}]},{"type":"paragraph","children":[{"type":"text","text":"24. At the completion of their shift or when being relieved shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"brief the relieving booking officer of all pertinent information with regard to prisoners in"}]}]},{"type":"paragraph","children":[{"type":"text","text":"custody"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"physically attend and conduct a cell check together with the relieving booking officer and"}]}]},{"type":"paragraph","children":[{"type":"text","text":"record the cell check information in the Cell Check screen and in their memorandum book"}]},{"type":"paragraph","children":[{"type":"text","text":"Designated Operator"}]},{"type":"paragraph","children":[{"type":"text","text":"The member designated to operate the audio/video equipment."}]},{"type":"paragraph","children":[{"type":"text","text":"25. After the person has been lodged in a cell shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"monitor the person"}]},{"type":"list-item","children":[{"type":"text","text":"notify the Officer in Charge in the event of any emergency incident involving the person"}]}]},{"type":"paragraph","children":[{"type":"text","text":"including, but not limited to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"sickness and medical treatment"}]},{"type":"list-item","children":[{"type":"text","text":"any injury or attempt suicide"}]},{"type":"list-item","children":[{"type":"text","text":"any assault, aggressive or bizarre behaviour"}]},{"type":"list-item","children":[{"type":"text","text":"any event which is likely to result in a complaint or SIU investigation"}]},{"type":"list-item","children":[{"type":"text","text":"any change in condition of persons in custody"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the DAMS units are operating properly"}]},{"type":"list-item","children":[{"type":"text","text":"immediately notify the Officer in Charge if the equipment malfunctions"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Officer in Charge"}]},{"type":"paragraph","children":[{"type":"text","text":"26. When notified about a prisoner who, due to their mental, physical or emotional condition, requires"}]},{"type":"paragraph","children":[{"type":"text","text":"priority in booking and processing to decrease the likelihood of a confrontation or safety risk shall"}]},{"type":"paragraph","children":[{"type":"text","text":"process the prisoner as soon as practicable."}]},{"type":"paragraph","children":[{"type":"text","text":"27. When a person in custody is brought into the station shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"consider whether the circumstances of the arrest and continued detention is lawful and"}]}]},{"type":"paragraph","children":[{"type":"text","text":"required"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the person has been informed of the reasons for the arrest"}]},{"type":"list-item","children":[{"type":"text","text":"evaluate the physical and mental state of the person"}]},{"type":"list-item","children":[{"type":"text","text":"inquire into any"}]},{"type":"list-item","children":[{"type":"text","text":"suicidal behaviour"}]},{"type":"list-item","children":[{"type":"text","text":"existing injury and related circumstances"}]},{"type":"list-item","children":[{"type":"text","text":"existing medical condition, including but not limited to: physical illness, mental illness,"}]}]},{"type":"paragraph","children":[{"type":"text","text":"alcohol use and/or addiction, drug use and/or addiction"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"safety concerns"}]},{"type":"list-item","children":[{"type":"text","text":"other self–disclosed condition to which police should be alerted"}]}]},{"type":"paragraph","children":[{"type":"text","text":"and comply with Appendix A, and make necessary notations in the appropriate Arrest"}]},{"type":"paragraph","children":[{"type":"text","text":"Booking/Cell Management screen, if applicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the person is transported to hospital, if required"}]},{"type":"list-item","children":[{"type":"text","text":"inquire if the person has an item of religious significance on their person or in their"}]}]},{"type":"paragraph","children":[{"type":"text","text":"possession, and comply with item 32, if applicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"inquire if the person has personal gender-affirming articles or gender-affirming prosthetics on"}]}]},{"type":"paragraph","children":[{"type":"text","text":"their person or in their possession, and comply with item 30, if applicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the person has been informed of the right to counsel, including the availability of free"}]}]},{"type":"paragraph","children":[{"type":"text","text":"legal advice through Duty Counsel and Legal Aid"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure reasonable access to a telephone is afforded as soon as practicable and “no call"}]}]},{"type":"paragraph","children":[{"type":"text","text":"desired” or the telephone number is recorded in the Arrest Booking/Cell Management screen"}]},{"type":"paragraph","children":[{"type":"text","text":" Telephone conversations with counsel shall be in private where conversations"}]},{"type":"paragraph","children":[{"type":"text","text":"cannot be overheard."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the necessary notations are made in the Arrest Booking/Cell Management screen"}]},{"type":"list-item","children":[{"type":"text","text":"record all pertinent information in the memorandum book"}]}]},{"type":"paragraph","children":[{"type":"text","text":"28. When a person in custody has a disability requiring the aid of an assistive device"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"shall assess whether to permit the person to keep their assistive device by"}]},{"type":"list-item","children":[{"type":"text","text":"considering all risk factors, including those contained in Procedure 01–02 Appendix B"}]},{"type":"list-item","children":[{"type":"text","text":"considering all available accommodation options, such as placing the person in a"}]}]},{"type":"paragraph","children":[{"type":"text","text":"segregated cell"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"should permit the person to keep their device while in custody, if possible"}]},{"type":"list-item","children":[{"type":"text","text":"upon determining that a person in custody cannot be accommodated, shall clearly articulate"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the reasons for the determination in the memorandum book, including all accommodation"}]},{"type":"paragraph","children":[{"type":"text","text":"options considered"}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments of whether a person should be permitted to keep their assistive device"}]},{"type":"paragraph","children":[{"type":"text","text":"while in custody shall be made on a case-by-case basis."}]},{"type":"paragraph","children":[{"type":"text","text":"29. When a person in custody is accompanied by a guide dog shall comply with Procedure 01–01."}]},{"type":"paragraph","children":[{"type":"text","text":"30. When a person in custody has gender-affirming personal items or gender-affirming prosthetics on"}]},{"type":"paragraph","children":[{"type":"text","text":"their person or in their possession shall:"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"assess whether to permit the person to keep their gender affirming item or gender-affirming"}]}]},{"type":"paragraph","children":[{"type":"text","text":"prosthetic"}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the retention of gender-affirming personal articles including"}]},{"type":"paragraph","children":[{"type":"text","text":"gender-affirming prosthetics shall be made on a case by case basis complying with"}]},{"type":"paragraph","children":[{"type":"text","text":"1.9.2 Standards of Conduct considering all risk factors, including those contained in"}]},{"type":"paragraph","children":[{"type":"text","text":"01-02 Appendix B, 01-02 Appendix C and Appendix E. All available accommodation"}]},{"type":"paragraph","children":[{"type":"text","text":"options shall be considered when making an assessment."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"permit the person to keep their item/device to the point of undue hardship"}]},{"type":"list-item","children":[{"type":"text","text":"if allowing the person to retain the item, make the appropriate notation in the Property"}]}]},{"type":"paragraph","children":[{"type":"text","text":"screen"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"upon determining that a person in custody cannot be accommodated, shall clearly articulate"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the reasons for the determination in the memorandum book and the Booking and Search"}]},{"type":"paragraph","children":[{"type":"text","text":"Template, including all accommodation options considered"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"if removing the item from the person, do so in compliance with Procedure 01-02 Appendix C"}]}]},{"type":"paragraph","children":[{"type":"text","text":"and Appendix E"}]},{"type":"paragraph","children":[{"type":"text","text":"31. When notified in accordance with items 18 and 25 that a decision regarding a person’s"}]},{"type":"paragraph","children":[{"type":"text","text":"accommodation while in custody requires reassessment, due to a change in circumstances, shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"reassess the situation accordingly"}]},{"type":"list-item","children":[{"type":"text","text":"ensure all pertinent details regarding the reassessment are recorded in the Arrest"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Booking/Cell Management screen"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"record all pertinent details regarding the reassessment in the memorandum book"}]}]},{"type":"paragraph","children":[{"type":"text","text":"32. When removing personal property from persons in custody shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"prior to removing the property, the person is informed of the safety concerns that require its"}]}]},{"type":"paragraph","children":[{"type":"text","text":"removal"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the property is removed, inventoried and secured in a property bag in compliance with"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Procedures 01–02, 09–01 and 09–06"}]},{"type":"paragraph","children":[{"type":"text","text":" The property bag may remain unsealed for investigative purposes providing it is in a"}]},{"type":"paragraph","children":[{"type":"text","text":"secured location, but must be sealed prior to transport. The sealed property bag"}]},{"type":"paragraph","children":[{"type":"text","text":"shall accompany the prisoner through the justice system."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the person’s money is counted and other property are inventoried aloud and on camera in the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"presence of the individual"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"all money and property are recorded in the Property screen"}]},{"type":"list-item","children":[{"type":"text","text":"the person signs the Property form, as directed in Procedure 09–06"}]},{"type":"list-item","children":[{"type":"text","text":"the property is inventoried on camera as it is returned to the person upon their release from"}]}]},{"type":"paragraph","children":[{"type":"text","text":"custody"}]},{"type":"paragraph","children":[{"type":"text","text":"33. When a person in custody has an item of religious significance on their person or in their possession"}]},{"type":"paragraph","children":[{"type":"text","text":"shall:"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"evaluate the safety risks that may result from allowing the person to retain the item"}]},{"type":"list-item","children":[{"type":"text","text":"if allowing the person to retain the item, make the appropriate notation in the Property screen"}]},{"type":"list-item","children":[{"type":"text","text":"if removing the item from the person, do so in compliance with Procedure 01–02 Appendix D"}]}]},{"type":"paragraph","children":[{"type":"text","text":"34. When a person in custody has apparently consumed liquor shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the arresting police officer has complied with Procedure 03–05, if the person is"}]}]},{"type":"paragraph","children":[{"type":"text","text":"intoxicated"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure compliance with Procedure 07–09 and 13–19, as applicable"}]},{"type":"list-item","children":[{"type":"text","text":"inquire when the person had their last drink"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the appropriate entries are made on the TPS 300 and the Arrest Booking/Cell"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Management screen for each booking process, if applicable"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure compliance with Procedure 06–11, if applicable"}]}]},{"type":"paragraph","children":[{"type":"text","text":"35. If the behaviour of the person is inconsistent with the amount of alcohol apparently consumed, or"}]},{"type":"paragraph","children":[{"type":"text","text":"is suspected to be caused by factors other than alcohol (e.g. methanol, cocaine, etc.) shall"}]},{"type":"paragraph","children":[{"type":"text","text":"comply with the Prisoner Safety section of Appendix A."}]},{"type":"paragraph","children":[{"type":"text","text":"36. Upon determining the detention of the person is not required shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"release the person in compliance with the appropriate release procedures in Chapter 1"}]},{"type":"list-item","children":[{"type":"text","text":"when the person in custody is a young person, ensure a parent, legal guardian, adult relative,"}]}]},{"type":"paragraph","children":[{"type":"text","text":"adult friend or spouse is notified without delay and requested to attend the station"}]},{"type":"paragraph","children":[{"type":"text","text":"37. Upon determining the detention of the person is necessary shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the investigation is continued by the arresting officer and/or by the appropriate"}]}]},{"type":"paragraph","children":[{"type":"text","text":"detective personnel"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure front line officers are returned to active duty as soon as practicable"}]},{"type":"list-item","children":[{"type":"text","text":"only permit the following individuals to interview a person in custody"}]},{"type":"list-item","children":[{"type":"text","text":"police officers involved in the investigation"}]},{"type":"list-item","children":[{"type":"text","text":"defence counsel"}]},{"type":"list-item","children":[{"type":"text","text":"members of law enforcement or government agencies involved in the investigation, at the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"request of the investigating officer"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"crown attorney or assistant"}]},{"type":"list-item","children":[{"type":"text","text":"a parent, relative, spouse or adult friend (young person only)"}]},{"type":"list-item","children":[{"type":"text","text":"spouse or immediate relative (at conclusion of investigation only)"}]},{"type":"list-item","children":[{"type":"text","text":"a consular official, where the person in custody is a foreign national as defined in"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Procedure 04–13"}]},{"type":"paragraph","children":[{"type":"text","text":"38. Upon determining a person in custody will be turned over to another law enforcement agency for"}]},{"type":"paragraph","children":[{"type":"text","text":"investigation shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"front line officers are returned to active duty as soon as practicable"}]},{"type":"list-item","children":[{"type":"text","text":"the applicable eReports and the Arrest Booking/Cell Management screen have been properly"}]}]},{"type":"paragraph","children":[{"type":"text","text":"completed"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the receiving law enforcement agency is made aware of any pertinent information regarding"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the person in custody including, but not limited to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"known or suspected suicidal tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"violent tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"serious medical conditions"}]},{"type":"list-item","children":[{"type":"text","text":"assistive devices"}]},{"type":"list-item","children":[{"type":"text","text":"safety concerns"}]},{"type":"list-item","children":[{"type":"text","text":"injuries"}]},{"type":"list-item","children":[{"type":"text","text":"emotional disturbance, any known mental illness or developmental disability"}]},{"type":"list-item","children":[{"type":"text","text":"medication, or whether any medication has been administered"}]},{"type":"list-item","children":[{"type":"text","text":"impairment due to alcohol or drugs"}]},{"type":"list-item","children":[{"type":"text","text":"accommodations to protect the rights of a trans or gender diverse person"}]}]},{"type":"paragraph","children":[{"type":"text","text":"39. Upon completion of an investigation shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the applicable eReports and the Arrest Booking/Cell Management screen have been"}]}]},{"type":"paragraph","children":[{"type":"text","text":"properly completed and the required documents have been scanned and attached to the"}]},{"type":"paragraph","children":[{"type":"text","text":"original eReport"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when the person in custody is a young person, ensure the YCJA Parent is completed and"}]}]},{"type":"paragraph","children":[{"type":"text","text":"served at the station, whenever possible"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"release or continue to detain the person in compliance with the applicable procedures"}]}]},{"type":"paragraph","children":[{"type":"text","text":"40. When receiving a person for lodging in police cells shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"female prisoners are"}]},{"type":"list-item","children":[{"type":"text","text":"segregated from male prisoners when it is necessary to place them in police cells, or"}]},{"type":"list-item","children":[{"type":"text","text":"transported to 55 Division, which is the only lock–up designated to receive female"}]}]},{"type":"paragraph","children":[{"type":"text","text":"prisoners"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"accused young persons are segregated from adult prisoners when it is necessary to detain"}]}]},{"type":"paragraph","children":[{"type":"text","text":"them in a divisional cell pending release or transport to a young persons’ lock–up"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"all members responsible for monitoring the condition of persons in police cells are made"}]}]},{"type":"paragraph","children":[{"type":"text","text":"aware of any pertinent information regarding the person including, but not limited to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"known or suspected suicidal tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"violent tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"serious medical conditions"}]},{"type":"list-item","children":[{"type":"text","text":"assistive devices"}]},{"type":"list-item","children":[{"type":"text","text":"safety concerns"}]},{"type":"list-item","children":[{"type":"text","text":"injuries"}]},{"type":"list-item","children":[{"type":"text","text":"emotional disturbance, any known mental illness or developmental disability"}]},{"type":"list-item","children":[{"type":"text","text":"medication, or whether any medication has been administered"}]},{"type":"list-item","children":[{"type":"text","text":"impairment due to alcohol or drugs"}]},{"type":"list-item","children":[{"type":"text","text":"individuals suspected of having suicidal or violent tendencies or serious medical conditions"}]}]},{"type":"paragraph","children":[{"type":"text","text":"are more closely monitored and checked as frequently as possible"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"trans persons are lodged in compliance with Appendix E"}]},{"type":"list-item","children":[{"type":"text","text":"a copy of all required eReports accompany the prisoner and that such reports are complete"}]}]},{"type":"paragraph","children":[{"type":"text","text":"and accurate"}]},{"type":"paragraph","children":[{"type":"text","text":"41. When there are persons lodged in the police cells shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"compliance with Procedure 03–07"}]},{"type":"list-item","children":[{"type":"text","text":"the cells are physically attended to check the condition of persons detained in custody"}]},{"type":"list-item","children":[{"type":"text","text":"a target of 30 minutes is used between physical cell checks having regard for all the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"circumstances during the tour of duty"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the cell checks are recorded in the Cell Check screen as directed in Appendix B"}]},{"type":"list-item","children":[{"type":"text","text":"any change in the condition of a person in custody is reviewed"}]},{"type":"list-item","children":[{"type":"text","text":"necessary medical attention is given to the person"}]},{"type":"list-item","children":[{"type":"text","text":"all property brought to the police facility for a person in custody is checked for contraband"}]}]},{"type":"paragraph","children":[{"type":"text","text":"before allowing the person access to the property"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the physical and medical condition of persons in police cells are reviewed with the relieving"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Officer in Charge at the change of shift"}]},{"type":"paragraph","children":[{"type":"text","text":"42. Prior to a person being transported to a lock–up, criminal court or detention centre shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"necessary medical attention is given to the person"}]},{"type":"list-item","children":[{"type":"text","text":"the necessary eReports are completed for a first court appearance in compliance with"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Procedure 12–01"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"compliance with Procedure 01–15, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"the Officer in Charge of the destination lock–up is advised when a person is to be transported"}]}]},{"type":"paragraph","children":[{"type":"text","text":"to the lock–up"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the officer advises the transporting officers and the Officer in Charge of the receiving facility"}]}]},{"type":"paragraph","children":[{"type":"text","text":"of any known issues regarding the health and safety of the person, including"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"known or suspected suicidal tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"violent tendencies, and/or"}]},{"type":"list-item","children":[{"type":"text","text":"a serious medical condition"}]},{"type":"list-item","children":[{"type":"text","text":"injuries"}]},{"type":"list-item","children":[{"type":"text","text":"assistive devices"}]},{"type":"list-item","children":[{"type":"text","text":"safety concerns"}]},{"type":"list-item","children":[{"type":"text","text":"emotional disturbance, any known mental illness or developmental disability"}]},{"type":"list-item","children":[{"type":"text","text":"medication, or whether any medication has been administered"}]},{"type":"list-item","children":[{"type":"text","text":"impairment due to alcohol or drugs"}]},{"type":"list-item","children":[{"type":"text","text":"sufficient police escort is provided"}]},{"type":"list-item","children":[{"type":"text","text":"the person''s property is handled in compliance with Procedure 09–06"}]},{"type":"list-item","children":[{"type":"text","text":"prescribed medication and a Medication Report accompanies the prisoner"}]}]},{"type":"paragraph","children":[{"type":"text","text":"43. When in charge of a unit with audio/video equipment in the detention facility shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"persons in custody are booked and released on camera"}]},{"type":"list-item","children":[{"type":"text","text":"equipment is operated by trained designated operators in compliance with this Procedure"}]},{"type":"list-item","children":[{"type":"text","text":"the completed BHS DVD and TPS 175 are submitted by the booking officer for review"}]},{"type":"list-item","children":[{"type":"text","text":"the MPVD# from the BHS DVD is entered on the TPS 192, and the completed BHS DVD and"}]}]},{"type":"paragraph","children":[{"type":"text","text":"TPS 175 are deposited in the transport bin"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the DAMS is operating properly"}]},{"type":"list-item","children":[{"type":"text","text":"requests for repairs or adjustments to the equipment are reported to the Help Desk"}]},{"type":"list-item","children":[{"type":"text","text":"appropriate entries are recorded for each person in the Arrest Booking/Cell Management"}]}]},{"type":"paragraph","children":[{"type":"text","text":"screen"}]},{"type":"paragraph","children":[{"type":"text","text":"44. When a prisoner claims to be a methadone patient shall ensure that such persons are informed"}]},{"type":"paragraph","children":[{"type":"text","text":"that their prescribed dosage can only be obtained"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"following release from custody, or"}]},{"type":"list-item","children":[{"type":"text","text":"if remanded in custody, by request to corrections staff and after corrections staff has"}]}]},{"type":"paragraph","children":[{"type":"text","text":"consulted with the prescribing doctor."}]},{"type":"paragraph","children":[{"type":"text","text":"45. When the prisoner complains of symptoms associated with the non-receipt of their prescription,"}]},{"type":"paragraph","children":[{"type":"text","text":"shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"medical advice (i.e. Telehealth Ontario) is sought, or the person is transported to a hospital"}]}]},{"type":"paragraph","children":[{"type":"text","text":"for assessment by a doctor for short term health risks"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"while in police custody, such persons are not transported for treatment at any place other"}]}]},{"type":"paragraph","children":[{"type":"text","text":"than a hospital"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"if the person is transported to a hospital, that staff are advised the purpose of the visit is not"}]}]},{"type":"paragraph","children":[{"type":"text","text":"to receive their prescribed dosage"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the results are noted in the crown brief, the Arrest Booking/Cell Management screen and the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Prisoner Transportation Report"}]},{"type":"paragraph","children":[{"type":"text","text":"46. If an incident occurs in an area being monitored and recorded by the DAMS shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure that assistance is immediately rendered and that the incident is dealt with in the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"appropriate manner"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"once the incident has been resolved, and it is determined that the recording should be"}]}]},{"type":"paragraph","children":[{"type":"text","text":"retained, notify PVEMU to retrieve and preserve the relevant security recording"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure the incident, along with a notation that the recording has been preserved, is made in"}]}]},{"type":"paragraph","children":[{"type":"text","text":"the appropriate Arrest Booking/Cell Management screen and the UCMR"}]},{"type":"paragraph","children":[{"type":"text","text":"Officer in Charge of a Lock–Up"}]},{"type":"paragraph","children":[{"type":"text","text":"47. When receiving a person for lodging in the cells, in addition to the duties of an Officer in Charge as"}]},{"type":"paragraph","children":[{"type":"text","text":"outlined in this Procedure shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"accept custody of the person where the original unit has complied with the applicable"}]}]},{"type":"paragraph","children":[{"type":"text","text":"procedures"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure relevant information concerning the person is recorded in the Arrest Booking/Cell"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Management screen"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"review the Prisoner Transportation Report for any cautions and remarks"}]},{"type":"list-item","children":[{"type":"text","text":"record any observations regarding a prisoner''s physical or mental condition"}]}]},{"type":"paragraph","children":[{"type":"text","text":"48. During the normal operating hours of criminal courts or detention centres shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"transport of the person from the lock–up at the earliest opportunity"}]},{"type":"list-item","children":[{"type":"text","text":"the transporting officers of the receiving facility are notified of any known issues regarding the"}]}]},{"type":"paragraph","children":[{"type":"text","text":"health and safety of the person, including"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"known or suspected suicidal tendencies"}]},{"type":"list-item","children":[{"type":"text","text":"violent tendencies, and/or"}]},{"type":"list-item","children":[{"type":"text","text":"a serious medical condition"}]},{"type":"list-item","children":[{"type":"text","text":"injuries"}]},{"type":"list-item","children":[{"type":"text","text":"assistive devices"}]},{"type":"list-item","children":[{"type":"text","text":"safety concerns"}]},{"type":"list-item","children":[{"type":"text","text":"emotional disturbance, any known mental illness or developmental disability"}]},{"type":"list-item","children":[{"type":"text","text":"medication, or whether any medication has been administered"}]},{"type":"list-item","children":[{"type":"text","text":"impairment due to alcohol or drugs"}]},{"type":"list-item","children":[{"type":"text","text":"a copy of the applicable eReports are attached to the Prisoner Transportation Report"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Case Manager"}]},{"type":"paragraph","children":[{"type":"text","text":"49. When a person is lawfully held in custody and an investigation is initiated shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"conduct a thorough investigation and advise the Officer in Charge of any information"}]}]},{"type":"paragraph","children":[{"type":"text","text":"pertaining to the release or detention of the person"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure front line officers are returned to active duty as soon as possible"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Detective Sergeant"}]},{"type":"paragraph","children":[{"type":"text","text":"50. The detective sergeant shall ensure an investigation is commenced in relation to the last drink"}]},{"type":"paragraph","children":[{"type":"text","text":"information received on the TPS 300, when required."}]},{"type":"paragraph","children":[{"type":"text","text":"Unit Commander"}]},{"type":"paragraph","children":[{"type":"text","text":"51. When in charge of a unit equipped with cells shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"designate a secure area for storage of returnable prisoners property that is inaccessible to"}]}]},{"type":"paragraph","children":[{"type":"text","text":"any person lodged in the cells"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure compliance with the requirement to perform and record cell checks in the Arrest"}]}]},{"type":"paragraph","children":[{"type":"text","text":"Booking/Cell Management screen"}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '01-03' LIMIT 1)
);

-- 4. Main roles
INSERT INTO main_roles (role_title, description, procedure_id) VALUES (
  'Police Officer',
  '[{"type":"paragraph","children":[{"type":"text","text":"When making an arrest shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"identify themselves as a police officer"}]},{"type":"list-item","children":[{"type":"text","text":"inform the person that they are under arrest"}]},{"type":"list-item","children":[{"type":"text","text":"inform the person of the reason for the arrest"}]},{"type":"list-item","children":[{"type":"text","text":"take physical control of the person"}]},{"type":"list-item","children":[{"type":"text","text":"inform the person of the Right to Counsel, including the existence and availability of duty"}]}]},{"type":"paragraph","children":[{"type":"text","text":"counsel and free legal advice (Legal Aid)"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"ensure that the person understands the Right to Counsel"}]},{"type":"list-item","children":[{"type":"text","text":"search the person in compliance with Procedure 01–02"}]},{"type":"list-item","children":[{"type":"text","text":"place the person in handcuffs in accordance with training and utilize the double lock"}]}]},{"type":"paragraph","children":[{"type":"text","text":"mechanism where possible"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when handcuffs are not used, be prepared to justify this decision"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Keeping in mind officer and public safety, officers may use discretion when"}]},{"type":"paragraph","children":[{"type":"text","text":"determining whether to handcuff an individual as it may not be practical or"}]},{"type":"paragraph","children":[{"type":"text","text":"necessary in all circumstances (e.g. due to a person’s medical condition, age,"}]},{"type":"paragraph","children":[{"type":"text","text":"disability, pregnancy, or frailty)."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"allow reasonable access to a telephone as soon as practicable"}]},{"type":"list-item","children":[{"type":"text","text":"ensure that, when an arrested person has the care, charge or custody of another person"}]}]},{"type":"paragraph","children":[{"type":"text","text":"who, because of age, physical or medical condition, is unable to care for themselves, every"}]},{"type":"paragraph","children":[{"type":"text","text":"effort is made to obtain interim care for the dependent person"}]},{"type":"paragraph","children":[{"type":"text","text":"2. In all cases of arrest, regardless of the authority used or whether charges are laid, shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"conduct a Person Query, including a CPIC check, obtaining details on any positive result"}]},{"type":"list-item","children":[{"type":"text","text":"record pertinent information in the memorandum book including, but not limited to"}]},{"type":"list-item","children":[{"type":"text","text":"reason for the arrest"}]},{"type":"list-item","children":[{"type":"text","text":"reason for the release or continued detention of the person"}]},{"type":"list-item","children":[{"type":"text","text":"all details regarding the person (identification and description)"}]},{"type":"list-item","children":[{"type":"text","text":"all other relevant details regarding the incident"}]},{"type":"list-item","children":[{"type":"text","text":"complete the applicable eReports"}]},{"type":"list-item","children":[{"type":"text","text":"comply with the applicable release/detention procedure"}]},{"type":"list-item","children":[{"type":"text","text":"if the arrest involves an arrest warrant, check the Master Name Index (MNI); note any"}]}]},{"type":"paragraph","children":[{"type":"text","text":"previous arrest number and case number and comply with the applicable procedure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 17–01, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"serve documents required for court on the person, if applicable"}]},{"type":"list-item","children":[{"type":"text","text":"submit all documents to the Officer in Charge prior to the completion of the tour of duty"}]}]},{"type":"paragraph","children":[{"type":"text","text":"3. When a non–violent person is arrested for being intoxicated in a public place shall comply with"}]},{"type":"paragraph","children":[{"type":"text","text":"Procedure 03–05."}]},{"type":"paragraph","children":[{"type":"text","text":"4. When dealing with an arrested person who has ingested a potentially harmful substance (e.g."}]},{"type":"paragraph","children":[{"type":"text","text":"cocaine, methanol, etc.) and appears to require medical attention shall immediately"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"if necessary, and if qualified in standard first aid, perform first aid on that person"}]},{"type":"list-item","children":[{"type":"text","text":"comply with Procedures 01–03 and 10–06"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the person is transported to the nearest hospital"}]}]},{"type":"paragraph","children":[{"type":"text","text":"5. When dealing with a prisoner who cannot communicate in English or has difficulty communicating"}]},{"type":"paragraph","children":[{"type":"text","text":"due to a medical problem shall comply with Procedure 04–09."}]},{"type":"paragraph","children":[{"type":"text","text":"6. When considering the continued detention of an arrested person who is accompanied by a guide"}]},{"type":"paragraph","children":[{"type":"text","text":"dog due to blindness, visual impairment, hearing impairment, or other physical disability, shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"make reasonable effort to have the guide dog accommodated by friends or relatives, or"}]}]},{"type":"paragraph","children":[{"type":"text","text":"contact the Toronto Police Operations Centre (TPOC) for further resources such as Canine"}]},{"type":"paragraph","children":[{"type":"text","text":"Vision Canada or the Humane Society"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"not transport the guide dog to court with the prisoner"}]}]},{"type":"paragraph","children":[{"type":"text","text":"When releasing a person following arrest shall make reasonable efforts to ensure the safety of"}]},{"type":"paragraph","children":[{"type":"text","text":"other persons who may be affected by the release and the safety of the person being released,"}]},{"type":"paragraph","children":[{"type":"text","text":"having regard for the circumstances and the time and place of release."}]},{"type":"paragraph","children":[{"type":"text","text":"8. When releasing a person on either a Form 9 or Form 10, or when proceeding by way of criminal"}]},{"type":"paragraph","children":[{"type":"text","text":"summons shall serve the person with a TPS 493."}]},{"type":"paragraph","children":[{"type":"text","text":"9. When dealing with an incident involving a person who provides identification as a diplomatic or"}]},{"type":"paragraph","children":[{"type":"text","text":"consular official shall"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"comply with Procedure 04–12"}]},{"type":"list-item","children":[{"type":"text","text":"not arrest a person on these premises"}]}]},{"type":"paragraph","children":[{"type":"text","text":" Foreign embassies and consulates are considered foreign land and outside the"}]},{"type":"paragraph","children":[{"type":"text","text":"jurisdiction of police officers."}]},{"type":"paragraph","children":[{"type":"text","text":"10. When arresting a foreign national"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"shall comply with Procedure 04–13"}]},{"type":"list-item","children":[{"type":"text","text":"should not normally arrest a person during a religious ceremony or judicial hearing"}]}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);
INSERT INTO main_roles (role_title, description, procedure_id) VALUES (
  'Officer in Charge',
  '[{"type":"paragraph","children":[{"type":"text","text":"11. When an arrest has been made shall ensure"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"consideration is given to the public interest in deciding to continue the detention of an"}]}]},{"type":"paragraph","children":[{"type":"text","text":"arrested person including the need to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"establish the identity of that person"}]},{"type":"list-item","children":[{"type":"text","text":"secure or preserve evidence"}]},{"type":"list-item","children":[{"type":"text","text":"prevent the continuation or repetition of an offence"}]},{"type":"list-item","children":[{"type":"text","text":"ensure that the accused will appear in court"}]},{"type":"list-item","children":[{"type":"text","text":"ensure the safety and security of any victim of or witness to the offence"}]},{"type":"list-item","children":[{"type":"text","text":"all required eReports are completed promptly"}]},{"type":"list-item","children":[{"type":"text","text":"the particulars are recorded in the Unit Commanders Morning Report (UCMR), as required"}]},{"type":"list-item","children":[{"type":"text","text":"compliance with the appropriate release provisions of the CC pursuant to the respective"}]}]},{"type":"paragraph","children":[{"type":"text","text":"procedure"}]},{"type":"paragraph","children":[{"type":"text","text":"12. When releasing a person shall ensure they have been served with a TPS 493."}]}]'::jsonb,
  (SELECT id FROM procedures WHERE procedure_number = '45292' LIMIT 1)
);

-- 5. Definitions (unique terms)
INSERT INTO definitions (term, definition)
VALUES ('Arrest', '[{"type":"paragraph","children":[{"type":"text","text":"Arrest means the act of restraining the liberty of a person with the intent to detain."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Assistive/Prosthetic Device', '[{"type":"paragraph","children":[{"type":"text","text":"Assistive/Prosthetic Device means a device used to replace, compensate for, or improve the functional abilities of people with disabilities or for trans or gender diverse persons to affirm gender identity. Assistive device includes a broad range of items such as mobility and visual/hearing aids, orthotics/prosthetics, speech devices, medical supplies, environmental controls and respiratory devices. Prosthetics used to express gender identity include: breast forms, chest binders, gaffs, packers, prosthetic penises and wigs."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Body Cavity Search (Formerly Level 4)', '[{"type":"paragraph","children":[{"type":"text","text":"Body Cavity Search (Formerly Level 4) – means a search of the rectum or vagina"}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Body Cavity Search Template', '[{"type":"paragraph","children":[{"type":"text","text":"Body Cavity Search Template means a document created to record the pertinent details of all Body Cavity searches. The template allows the Service to electronically capture the data required to properly report on all Body Cavity searches of persons (including self-identified transgender/transsexual persons) conducted by members."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Booking and Search Template', '[{"type":"paragraph","children":[{"type":"text","text":"Booking and Search Template means a document created to record the pertinent details of all Frisk & Strip searches and the authorization of a Body Cavity search. The template allows the Service to electronically capture the data required to properly report on all Frisk & Strip searches of persons (including self–identified transgender/transsexual persons) conducted by members. For prisoners that are booked into a police facility."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Booking Hall System (BHS)', '[{"type":"paragraph","children":[{"type":"text","text":"Booking Hall System (BHS) means a video surveillance system installed in the sally–port, booking hall and other areas of a police facility that is designed to record the booking and release of all prisoners as they enter and leave a police facility. The BHS is operated manually by the booking officer. (Booking Video)"}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Booking Officer', '[{"type":"paragraph","children":[{"type":"text","text":"Booking Officer means a police officer, court officer or custodial officer designated by the officer in charge as the person responsible for the care and handling of persons detained in custody."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Court Cells', '[{"type":"paragraph","children":[{"type":"text","text":"Court Cells means cells used during those hours in which the courts are sitting. A person shall be"}]},{"type":"paragraph","children":[{"type":"text","text":"lodged in a court cell when:"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"being held for a court appearance;"}]},{"type":"list-item","children":[{"type":"text","text":"awaiting transportation to a detention facility;"}]},{"type":"list-item","children":[{"type":"text","text":"ordered into custody by the court."}]}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Criminal Offence', '[{"type":"paragraph","children":[{"type":"text","text":"Criminal Offence means any offence against an Act of Parliament."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Designated Operator', '[{"type":"paragraph","children":[{"type":"text","text":"Designated Operator for the purposes persons in custody means any member designated as an"}]},{"type":"paragraph","children":[{"type":"text","text":"audio/video operator with an understanding of how to operate the equipment."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Detention Area Monitoring System (DAMS)', '[{"type":"paragraph","children":[{"type":"text","text":"Detention Area Monitoring System (DAMS) means a video surveillance system installed in the"}]},{"type":"paragraph","children":[{"type":"text","text":"prisoner detention areas of a police facility, such as the cells and the bullpen, which is designed to"}]},{"type":"paragraph","children":[{"type":"text","text":"monitor and record the condition of prisoners while they are in custody. The DAMS is set to"}]},{"type":"paragraph","children":[{"type":"text","text":"automatically record each cell and bullpen when activity is detected. (Cell Video)"}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Detention Facility', '[{"type":"paragraph","children":[{"type":"text","text":"Detention Facility means any central lock–up and/or booking hall."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Disability', '[{"type":"paragraph","children":[{"type":"text","text":"Disability means:"}]},{"type":"paragraph","children":[{"type":"text","text":"a) any degree of physical disability, infirmity, malformation or disfigurement that is caused by"}]},{"type":"paragraph","children":[{"type":"text","text":"bodily injury, birth defect or illness and, without limiting the generality of the foregoing, includes"}]},{"type":"paragraph","children":[{"type":"text","text":"diabetes mellitus, epilepsy, a brain injury, any degree of paralysis, amputation, lack of physical"}]},{"type":"paragraph","children":[{"type":"text","text":"co-ordination, blindness or visual impediment, deafness or hearing impediment, muteness or"}]},{"type":"paragraph","children":[{"type":"text","text":"speech impediment, or physical reliance on a guide dog or other animal or on a wheelchair or"}]},{"type":"paragraph","children":[{"type":"text","text":"other remedial appliance or device"}]},{"type":"paragraph","children":[{"type":"text","text":"b) condition of mental impairment or a developmental disability;"}]},{"type":"paragraph","children":[{"type":"text","text":"c) a learning disability, or a dysfunction in one or more of the processes involved in understanding"}]},{"type":"paragraph","children":[{"type":"text","text":"or using symbols or spoken language;"}]},{"type":"paragraph","children":[{"type":"text","text":"d) a mental disorder, or;"}]},{"type":"paragraph","children":[{"type":"text","text":"e) an injury or disability for which benefits were claimed or received under the insurance plan"}]},{"type":"paragraph","children":[{"type":"text","text":"established under the Workplace Safety and Insurance Act; (“handicap”)"}]},{"type":"paragraph","children":[{"type":"text","text":"[Source: Ontario Human Rights Code, Accessibility for Ontarians with Disabilities Act]."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Divisional Cells', '[{"type":"paragraph","children":[{"type":"text","text":"Divisional Cells means cells that may be used for short term detention of a person in custody when:"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"being processed, or waiting to be processed, or to ensure the safety of the person and/or"}]}]},{"type":"paragraph","children":[{"type":"text","text":"members;"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"awaiting transportation to a central lock–up;"}]},{"type":"list-item","children":[{"type":"text","text":"being held for return by an outside agency."}]}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Frisk Search (Formerly Level 2)', '[{"type":"paragraph","children":[{"type":"text","text":"Frisk Search (Formerly Level 2) – This is used generally for Search Incident to Arrest and means a"}]},{"type":"paragraph","children":[{"type":"text","text":"more-thorough search that may include emptying and searching pockets as well as removal of"}]},{"type":"paragraph","children":[{"type":"text","text":"clothing, which does not expose a person’s undergarments, or the areas of the body normally"}]},{"type":"paragraph","children":[{"type":"text","text":"covered by undergarments. The removal of clothing such as belts, footwear, socks, shoes, sweaters,"}]},{"type":"paragraph","children":[{"type":"text","text":"extra layers of clothing, or the shirt of a male would all be included in a Frisk search. A Frisk search"}]},{"type":"paragraph","children":[{"type":"text","text":"may be commenced in the field and concluded at the station."}]},{"type":"paragraph","children":[{"type":"text","text":"A Frisk search conducted incident to arrest includes the area within the immediate control of the"}]},{"type":"paragraph","children":[{"type":"text","text":"arrested person."}]},{"type":"paragraph","children":[{"type":"text","text":"Members shall make every effort to video and audio record all Frisk searches. Members are also"}]},{"type":"paragraph","children":[{"type":"text","text":"required to articulate the justification for the manner and circumstances under which these searches"}]},{"type":"paragraph","children":[{"type":"text","text":"are conducted. For the purposes of this definition, “Pat Down Search” means the same as, “Frisk"}]},{"type":"paragraph","children":[{"type":"text","text":"Search”."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Gender', '[{"type":"paragraph","children":[{"type":"text","text":"Gender: the set of socially classified behaviours, attitudes and norms associated with and roles of"}]},{"type":"paragraph","children":[{"type":"text","text":"men, women, trans people, non-binary people and more. Encompasses gender identity, a person’s"}]},{"type":"paragraph","children":[{"type":"text","text":"internal sense of being a man, woman, both or neither."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Gender Expression', '[{"type":"paragraph","children":[{"type":"text","text":"Gender Expression is how a person publicly presents their gender. This can include behaviour and"}]},{"type":"paragraph","children":[{"type":"text","text":"outward appearance such as dress, hair, make-up, body language and voice. A person’s chosen name"}]},{"type":"paragraph","children":[{"type":"text","text":"and pronoun are also common and important ways of expressing gender."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Gender Identity', '[{"type":"paragraph","children":[{"type":"text","text":"Gender identity is each person’s internal and individual experience of gender. It is their sense of being"}]},{"type":"paragraph","children":[{"type":"text","text":"a woman, a man, both, neither, or anywhere along or beyond the gender spectrum. A person’s gender"}]},{"type":"paragraph","children":[{"type":"text","text":"identity may be the same as or different from the typical pairing with their birth-assigned sex. Gender"}]},{"type":"paragraph","children":[{"type":"text","text":"identity is fundamentally different from a person’s sexual orientation."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Gender identity', '[{"type":"paragraph","children":[{"type":"text","text":"Gender identity is each person’s internal and individual experience of gender. It is their sense of"}]},{"type":"paragraph","children":[{"type":"text","text":"being a woman, a man, both, neither, or anywhere along or beyond the gender spectrum. A person’s"}]},{"type":"paragraph","children":[{"type":"text","text":"gender identity may be the same as or different from the typical pairing with their birth-assigned sex."}]},{"type":"paragraph","children":[{"type":"text","text":"Gender identity is fundamentally different from a person’s sexual orientation."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Handheld Metal Detector', '[{"type":"paragraph","children":[{"type":"text","text":"Handheld Metal Detector means a portable, handheld security device capable of detecting metal objects authorized for use by the Service."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Indictable Offence', '[{"type":"paragraph","children":[{"type":"text","text":"Indictable Offence means any offence against an Act of Parliament."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Item of Religious Significance', '[{"type":"paragraph","children":[{"type":"text","text":"Item of Religious Significance means any item, article, apparel, or clothing a person identifies as"}]},{"type":"paragraph","children":[{"type":"text","text":"having religious importance."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Lock-Up', '[{"type":"paragraph","children":[{"type":"text","text":"Lock–Up means an assigned division used to detain a person in custody:"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when the person is held for a Show Cause hearing, or Judicial Interim Release where the bail"}]}]},{"type":"paragraph","children":[{"type":"text","text":"court is closed"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"when outside of admitting hours stipulated in Procedure 03–03"}]},{"type":"list-item","children":[{"type":"text","text":"in any other circumstances where detention is authorized and necessary."}]}]},{"type":"paragraph","children":[{"type":"text","text":"See Appendix C for a list of assigned lock–ups."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Member – Prisoner Care & Control', '[{"type":"paragraph","children":[{"type":"text","text":"Member – Prisoner Care & Control for the purposes of prisoner transportation, care and control,"}]},{"type":"paragraph","children":[{"type":"text","text":"includes a police officer, court officer and custodial officer."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Non-binary', '[{"type":"paragraph","children":[{"type":"text","text":"Non-binary gender identities outside of the expected binary of men and women.Non-binary gender identities outside of the expected binary of men and women."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Police Cells', '[{"type":"paragraph","children":[{"type":"text","text":"Police Cells means divisional cells, central lock–ups and court cells used for the secure detention of"}]},{"type":"paragraph","children":[{"type":"text","text":"persons in custody. An interview room is not a police cell."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Police Vehicle – Prisoner Transportation', '[{"type":"paragraph","children":[{"type":"text","text":"Police Vehicle – Prisoner Transportation for the purposes of prisoner transportation, includes"}]},{"type":"paragraph","children":[{"type":"text","text":"marked and unmarked vehicle owned or operated by the Service, that has the capacity to transport a"}]},{"type":"paragraph","children":[{"type":"text","text":"driver and two or more passengers."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Protective Search (Formerly Level 1)', '[{"type":"paragraph","children":[{"type":"text","text":"Protective Search (Formerly Level 1) – This is used generally during Investigative Detention and"}]},{"type":"paragraph","children":[{"type":"text","text":"involves a limited search of a person who has been detained by police when there is reasonable"}]},{"type":"paragraph","children":[{"type":"text","text":"belief the person poses a safety risk. The scope of the search is limited to exterior patting of clothing"}]},{"type":"paragraph","children":[{"type":"text","text":"such as pockets, waistband or areas that may reasonably conceal such items as weapons or"}]},{"type":"paragraph","children":[{"type":"text","text":"implements that may be used as weapons, usually with open hands to maximize the ability to detect"}]},{"type":"paragraph","children":[{"type":"text","text":"weapons through clothing. This search may also be described as a “safety search”, as that is the"}]},{"type":"paragraph","children":[{"type":"text","text":"purpose and objective."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Reasonable Groundsmeans', '[{"type":"paragraph","children":[{"type":"text","text":"Reasonable Groundsmeans a set of facts or circumstances that would lead a person of ordinary care and judgement to have a strong belief beyond mere suspicion."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Search in the Field Only Template', '[{"type":"paragraph","children":[{"type":"text","text":"Search in the Field Only Template means a document created to record the pertinent details of all"}]},{"type":"paragraph","children":[{"type":"text","text":"Protective and Frisk searches that occur in the field where a person has not been brought into a police"}]},{"type":"paragraph","children":[{"type":"text","text":"facility. The template allows the Service to electronically capture the data required to properly report on"}]},{"type":"paragraph","children":[{"type":"text","text":"all searches of persons (including self–identified transgender/transsexual persons) conducted by"}]},{"type":"paragraph","children":[{"type":"text","text":"members that have occurred in the field where the person was not brought in to a police facility."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Service Members’ Perception Data', '[{"type":"paragraph","children":[{"type":"text","text":"Service Members’ Perception Data means information derived from a member making a determination with respect to the race of an individual by observation, solely on the basis of that member’s own perception."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Sex', '[{"type":"paragraph","children":[{"type":"text","text":"Sex: the classification of people as male, female or intersex based on a specific combination of"}]},{"type":"paragraph","children":[{"type":"text","text":"reproductive organs, chromosomes and hormones and assigned at birth based on observation of a"}]},{"type":"paragraph","children":[{"type":"text","text":"person’s genitals."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Strip Search (Formerly Level 3)', '[{"type":"paragraph","children":[{"type":"text","text":"Strip Search (Formerly Level 3) – R. vs. Golden 2001 SCC 83 established that which constitutes a"}]},{"type":"paragraph","children":[{"type":"text","text":"strip search and what types of circumstances may justify one. A Strip search includes all steps in"}]},{"type":"paragraph","children":[{"type":"text","text":"Protective and Frisk searches as well as a thorough search of a person’s clothing and non-physical"}]},{"type":"paragraph","children":[{"type":"text","text":"search of the body. That will often require removal or rearrangement of some, or all, of the person’s"}]},{"type":"paragraph","children":[{"type":"text","text":"clothing to permit a visual inspection of a person’s private areas: namely the genitals, buttocks,"}]},{"type":"paragraph","children":[{"type":"text","text":"breasts or chest, body cavity, and/or undergarments; the mouth was excluded from this definition"}]},{"type":"paragraph","children":[{"type":"text","text":"despite being a bodily cavity."}]},{"type":"paragraph","children":[{"type":"text","text":"The Supreme Court noted that Strip searches “represent a significant invasion of privacy and are"}]},{"type":"paragraph","children":[{"type":"text","text":"often humiliating, degrading and traumatic” and therefore require “a higher degree of justification in"}]},{"type":"paragraph","children":[{"type":"text","text":"order to support the higher degree of interference with individual freedom and dignity.”"}]},{"type":"paragraph","children":[{"type":"text","text":"When considering whether a Strip search is justified, the Supreme Court stated, “In addition to"}]},{"type":"paragraph","children":[{"type":"text","text":"reasonable and probable grounds justifying the arrest, the police must establish reasonable and"}]},{"type":"paragraph","children":[{"type":"text","text":"probable grounds justifying the strip search,” and “the police must establish they have reasonable and"}]},{"type":"paragraph","children":[{"type":"text","text":"probable grounds for concluding that a strip search is necessary in the particular circumstances of the"}]},{"type":"paragraph","children":[{"type":"text","text":"arrest.”"}]},{"type":"paragraph","children":[{"type":"text","text":" The mere fact that portions of a person''s body normally covered by undergarments"}]},{"type":"paragraph","children":[{"type":"text","text":"are exposed because of the way the person was dressed when taken into custody"}]},{"type":"paragraph","children":[{"type":"text","text":"does not constitute a strip search, if the removal of such clothing was not caused by"}]},{"type":"paragraph","children":[{"type":"text","text":"the police (i.e. the arrest of a naked person does not in itself constitute a strip"}]},{"type":"paragraph","children":[{"type":"text","text":"search)."}]},{"type":"paragraph","children":[{"type":"text","text":" The rearrangement of clothing that permits a visual inspection of a person’s private"}]},{"type":"paragraph","children":[{"type":"text","text":"area constitutes a strip search."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Trans', '[{"type":"paragraph","children":[{"type":"text","text":"Trans is an umbrella term referring to people with diverse gender identities and expressions that differ from their assigned sex at birth. It includes but is not limited to people who identify as transgender, trans woman (someone assigned male at birth who knows themself to be a woman), trans man (someone assigned female at birth who knows themself to be a man), non-binary, gender non- conforming, gender variant or gender queer. Some people may consider two-spirit to be a trans identity. Trans persons may or may not make a social transition, have surgery, use prosthetic devices or take prescription medications (such as hormone therapies), to affirm their gender identity. They may or may not have identity documents that reflect their lived identity."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;
INSERT INTO definitions (term, definition)
VALUES ('Valuable Property', '[{"type":"paragraph","children":[{"type":"text","text":"Valuable Property means money, jewellery and other items that may make a prisoner the target of"}]},{"type":"paragraph","children":[{"type":"text","text":"theft or robbery."}]}]'::jsonb)
ON CONFLICT (term) DO NOTHING;

