INSERT INTO appendices (name, title, description, status, issue_date, replaces_date, procedure_id) VALUES (
  '01-02 App B',
  'Risk Assessment – Type of Search',
  '[{"type":"paragraph","children":[{"type":"text","text":"The right to search as an incident to a lawful arrest is found in common law, and has been upheld by the Supreme Court, as long as the search is conducted for a valid objective and is not conducted in an abusive fashion."}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"Cloutier v. Langlois (Supreme Court of Canada) (1990)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. Flintoff (Ontario Court of Appeal) (1998)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. Coulter (Ontario Court of Justice) (2000)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. Golden (Supreme Court of Canada) (2001)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. Clarke, Heroux and Pilipa (Ontario Superior Court of Justice) (2003)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. Mann (Supreme Court of Canada) (2004)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. McGuffie (Ontario Court of Appeal) (2016)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. MacPherson (Ontario Native Council on Justice) (2018)"}]},{"type":"list-item","children":[{"type":"text","text":"R. v. Tonkin (Ontario Superior Court of Justice) (2020)"}]}]},{"type":"paragraph","children":[{"type":"text","text":"As an incident to arrest a police officer may search for"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"weapons"}]},{"type":"list-item","children":[{"type":"text","text":"anything that could cause injury (including drugs and alcohol)"}]},{"type":"list-item","children":[{"type":"text","text":"anything that could assist in a person''s escape"}]},{"type":"list-item","children":[{"type":"text","text":"evidence"}]}]},{"type":"paragraph","children":[{"type":"text","text":"For safety reasons, every person who is brought into a police facility under arrest shall be subject to a search."}]},{"type":"paragraph","children":[{"type":"text","text":"When assessing the type of search, the Officer in Charge / police officer shall on a case by case basis, evaluate the circumstances relevant to the individual to be searched and determine the appropriate type of search required to address any risk factors, keeping in mind that the safety of the officers, the individual and to others is paramount. The Officer in Charge is responsible for ensuring that the type of search appropriately addresses the risk factors associated to the current arrest including those related to the person, and logistical issues such as the type of transportation and contact with others that this individual is expected to encounter."}]},{"type":"paragraph","children":[{"type":"text","text":"Strip Searches"}]},{"type":"paragraph","children":[{"type":"text","text":"In 2001, the Supreme Court of Canada, in the matter of R. v. Golden, while upholding the common law right to search a person who had been lawfully arrested, placed restrictions on police officers contemplating Strip searches."}]},{"type":"paragraph","children":[{"type":"text","text":"Risk Factors"}]},{"type":"paragraph","children":[{"type":"text","text":"Officers contemplating a Strip search of a person shall consider all the circumstances, including but not limited to"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"the details of the current arrest"}]},{"type":"list-item","children":[{"type":"text","text":"the history of the person"}]},{"type":"list-item","children":[{"type":"text","text":"any items already located on the person during a Protective or Frisk search"}]},{"type":"list-item","children":[{"type":"text","text":"the demeanour or mental state of the individual"}]},{"type":"list-item","children":[{"type":"text","text":"the risks to the individual, the police, or others, associated with not performing a Strip search"}]},{"type":"list-item","children":[{"type":"text","text":"the potential that the person will come into contact with other detainees, creating an"}]}]},{"type":"paragraph","children":[{"type":"text","text":"opportunity for the person to hand off contraband, weapons, etc...to another prisoner (R. v. Coulter)"}]},{"type":"paragraph","children":[{"type":"text","text":"In addition to any factors being considered pertaining to the individual person, the following set of circumstances represents the heightened safety concerns that are common to all persons held for a Show Cause hearing"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"lodged in a cell awaiting transportation"}]},{"type":"list-item","children":[{"type":"text","text":"direct contact with other prisoners during transportation and lodging, creating the potential for conflict and/or weapons/contraband being passed from one person to the next"}]},{"type":"list-item","children":[{"type":"text","text":"unsupervised while being transported in a prisoner transportation wagon"}]},{"type":"list-item","children":[{"type":"text","text":"lodged in court cells with other prisoners and prisoners arriving directly from the correctional system"}]},{"type":"list-item","children":[{"type":"text","text":"transportation, lodging, escorting of prisoner at court conducted by unarmed court officers"}]},{"type":"list-item","children":[{"type":"text","text":"direct contact with booking officers, court officers, correctional officers, lawyers, and other court staff who are unarmed and have an expectation that every prisoner has been thoroughly searched to ensure officer, prisoner and public safety"}]},{"type":"list-item","children":[{"type":"text","text":"the duty to protect prisoners while in custody and their expectation that while in custody their safety is not compromised"}]},{"type":"list-item","children":[{"type":"text","text":"the Officer in Charge cannot know the background/history/state of mind of all the prisoners that will be brought into the system on any given day, but is required to ensure their protection"}]}]},{"type":"paragraph","children":[{"type":"text","text":"All persons who are held in custody pending a Show Cause hearing are deemed to be entering the prison population. In assessing the appropriate type of search, the Officer in Charge shall take into account the heightened safety concerns created by this situation. Nevertheless the fact that a person is being held for a Show Cause hearing and may come into contact with other persons in custody does not, on its own, justify a Strip search. Members shall consult with the Officer in Charge prior to conducting a Strip search at a police station."}]},{"type":"paragraph","children":[{"type":"text","text":"Prohibitions"}]},{"type":"paragraph","children":[{"type":"text","text":"The Supreme Court has ruled that Strip searches in the field will only be justified where there is a demonstrated necessity and urgency to search for weapons or objects that could be used to threaten the safety of the accused, the arresting officers or other individuals. In this case, officers would have to show why it would have been unsafe to wait and conduct the search at the police station. Strip searches shall not be conducted in the field for the sole purpose of preserving evidence. When a Strip search must be conducted in the field, it will be done in a private area with only the searching officers able to view the person being searched, where possible. When a Strip search must be conducted in the field, the searching officers shall immediately notify the Officer in Charge upon their"}]},{"type":"paragraph","children":[{"type":"text","text":"arrival at the police station. Strip searches shall not be videotaped. Any benefit to videotaping the search is outweighed by the potential of causing unnecessary embarrassment to the person being searched. Further, in cases where a searching area has video equipment installed, the person being searched will be advised that"}]},{"type":"paragraph","children":[{"type":"text","text":"the search is not being videotaped."}]}]'::jsonb,
  'Amended',
  '2021-11-24',
  '2020-10-09',
  (SELECT id FROM procedures WHERE procedure_number = '01-02' LIMIT 1)
);
INSERT INTO appendices (name, title, description, status, issue_date, replaces_date, procedure_id) VALUES (
  '01-02 App C',
  'Trans Persons',
  '[{"type":"paragraph","children":[{"type":"text","text":"The Toronto Police Service recognizes that special arrangements may have to be made to accommodate trans persons."}]},{"type":"paragraph","children":[{"type":"text","text":"The term trans refers to people with diverse gender identities and expressions that differ from their assigned sex at birth."}]},{"type":"paragraph","children":[{"type":"text","text":"Gender Expression is how a person publicly presents their gender. This can include behaviour and outward appearance such as dress, hair, make-up, body language and voice. A person’s chosen name and pronoun are also common and important ways of expressing gender."}]},{"type":"paragraph","children":[{"type":"text","text":"Gender Identity is each person’s internal and individual experience of gender. It is their sense of being a woman, a man, both, neither, or anywhere along or beyond the gender spectrum. A person’s gender identity may be the same as or different from the typical pairing with their birth-assigned sex. Gender identity is fundamentally different from a person’s sexual orientation"}]},{"type":"paragraph","children":[{"type":"text","text":"Trans includes but is not limited to people who identify as transgender, trans woman (someone assigned male at birth who knows themself to be a woman), trans man (someone assigned female at birth who knows themself to be a man), non-binary, gender non-conforming, gender variant or gender queer. Some people may consider two-spirit to be a trans identity. Trans persons may or may not make a social transition, have surgery, use prosthetic devices or take prescription medications (such as hormone therapies), to affirm their gender identity. They may or may not have identity documents that reflect their lived identity. When interacting with trans persons, officers shall be sensitive to needs and concerns without jeopardizing officer and prisoner safety, and the need to perform a legal and thorough search."}]},{"type":"paragraph","children":[{"type":"text","text":"In order to best address the specific needs or concerns of each person, each case must be assessed individually. To that end, the Officer in Charge shall comply with 1.9.2 Standards of Conduct - Respect for Gender Diversity and Trans-Inclusive Policing) when determining the best possible course of action in order to respect the dignity of the person being searched."}]},{"type":"paragraph","children":[{"type":"text","text":"For the purpose of search, when an individual has self–identified as trans, the Officer in Charge shall"}]},{"type":"paragraph","children":[{"type":"text","text":" refer to the person in their chosen name and gender pronoun(s)"}]},{"type":"paragraph","children":[{"type":"text","text":" after discussion with the prisoner, lodge the prisoner according to their self-identified gender or lodging preference in accordance with 01-03 Appendix E unless it can be proven that there are specific overriding health and safety concerns that cannot be resolved, rendering the accommodation impossible. When a prisoner cannot be accommodated in this regard, members shall clearly articulate the reasons in their memorandum book; and"}]},{"type":"paragraph","children":[{"type":"text","text":" ensure that information regarding a trans prisoner’s gender identity or gender history is shared on a need-to-know basis only with those persons directly involved with the case"}]},{"type":"paragraph","children":[{"type":"text","text":" explain to the individual the following 3 options for a Search"}]},{"type":"paragraph","children":[{"type":"text","text":" male officers only or"}]},{"type":"paragraph","children":[{"type":"text","text":" female officers only or"}]},{"type":"paragraph","children":[{"type":"text","text":" a split search"}]},{"type":"paragraph","children":[{"type":"text","text":" the Officer in Charge shall be guided by the preference of the individual to be searched, in terms of the gender of the person conducting the search"}]},{"type":"paragraph","children":[{"type":"text","text":" when required to remove a gender-affirming article or prosthetic device/item (including breast forms, chest binders, gaffs, packers, prosthetic penises and wigs) from a trans or gender diverse person shall"}]},{"type":"paragraph","children":[{"type":"text","text":" advise the person of the reason for removing the device/item"}]},{"type":"paragraph","children":[{"type":"text","text":" provide the person with the opportunity to remove the device/item themselves when self removal does not pose potential risk of safety/injury to the person or member"}]},{"type":"paragraph","children":[{"type":"text","text":" be cognizant that trans and gender diverse persons may have an emotional as well as physical attachment to their gender affirming items and shall treat the device/items with respect at all times"}]},{"type":"paragraph","children":[{"type":"text","text":" in the case of prosthetic devices"}]},{"type":"paragraph","children":[{"type":"text","text":" whenever practicable allow for the removal of the device in a private area"}]},{"type":"paragraph","children":[{"type":"text","text":" when self-removal is not possible, ask the person how to properly remove the device"}]},{"type":"paragraph","children":[{"type":"text","text":" allow adequate space and range of motion for reattachment of the device"}]},{"type":"paragraph","children":[{"type":"text","text":" return the device/item to the person as soon as possible upon completion of the search"}]},{"type":"paragraph","children":[{"type":"text","text":" Assessments regarding the retention of gender-affirming personal articles including gender-affirming prosthetics shall be made on a case by case basis complying with 1.9.2 Standards of Conduct considering all risk factors, including those contained in Appendix B, Appendix C and 01-03 Appendix E. All available accommodation options shall be considered when making an assessment."}]},{"type":"paragraph","children":[{"type":"text","text":" When it is determined that a person cannot be accommodated, the reasons for the determination must be clearly documented in the memorandum book including all accommodation options considered."}]},{"type":"paragraph","children":[{"type":"text","text":" make appropriate entries in the memorandum book, including the Booking and Search template option selected by the person, and the rationale for the course of action taken"}]},{"type":"paragraph","children":[{"type":"text","text":" complete the appropriate sections of the Booking and Search template"}]},{"type":"paragraph","children":[{"type":"text","text":" Members shall document why particular actions were or were not taken."}]}]'::jsonb,
  'Amended',
  '2021-04-29',
  '2020-10-09',
  (SELECT id FROM procedures WHERE procedure_number = '01-02' LIMIT 1)
);
INSERT INTO appendices (name, title, description, status, issue_date, replaces_date, procedure_id) VALUES (
  '01-02 App D',
  'Handling of Religious Significance',
  '[{"type":"paragraph","children":[{"type":"text","text":"The Toronto Police Service recognizes that special arrangements may have to be made when handling items, articles, apparel, or clothing of religious importance (item of religious significance). Although there are a multitude of items of religious significance that differ between and amongst religions, any item of religious significance identified by a person shall be handled according to the process below."}]},{"type":"paragraph","children":[{"type":"text","text":"In addition to the process below, members should seek direction from the person regarding the handling of the item of religious significance and, if practicable, handle the item as requested by the person. In general, items of religious significance shall be treated with respect and handled appropriately."}]},{"type":"paragraph","children":[{"type":"text","text":"When handling the item of religious significance, members shallbe cognizant of human rights and unless circumstances make it impractical to do so, comply with the process below, having regard for the"}]},{"type":"list","format":"unordered","children":[{"type":"list-item","children":[{"type":"text","text":"immediate risk of injury"}]},{"type":"list-item","children":[{"type":"text","text":"immediate risk of escape"}]},{"type":"list-item","children":[{"type":"text","text":"immediate risk of destruction of evidence"}]},{"type":"list-item","children":[{"type":"text","text":"safety of the member"}]},{"type":"list-item","children":[{"type":"text","text":"safety of the person"}]},{"type":"list-item","children":[{"type":"text","text":"safety of the public."}]}]},{"type":"paragraph","children":[{"type":"text","text":"The following process shall be followed when handling an item of religious significance."}]},{"type":"paragraph","children":[{"type":"text","text":"Ask the person if they have an item of religious significance on their person or in their possession."}]},{"type":"paragraph","children":[{"type":"text","text":"1. Members shall advise the person if an item of religious significance will be removed, the reason the item is being removed, and provide the person with the opportunity to remove the item themselves if self–removal does not pose potential risk of safety/injury to the person or member."}]},{"type":"paragraph","children":[{"type":"text","text":"2. When practicable, members shall use gloves when handling an item of religious significance."}]},{"type":"paragraph","children":[{"type":"text","text":"3. When practicable, members shall facilitate the replacement of an item of religious significance as soon as possible when the item (apparel or clothing only) is removed and held for any purpose and is not being immediately returned to that person."}]},{"type":"paragraph","children":[{"type":"text","text":"4. Members shall place an item of religious significance in a separate property bag"}]},{"type":"paragraph","children":[{"type":"text","text":" In general, it is acceptable to store items of religious significance together in one"}]},{"type":"paragraph","children":[{"type":"text","text":"property bag."}]},{"type":"paragraph","children":[{"type":"text","text":"5. A sealed property bag containing an item of religious significance may be sealed within the main property bag when the person is being transported or held for a show cause hearing."}]}]'::jsonb,
  'Amended',
  '2020-01-03',
  '2013-10-30',
  (SELECT id FROM procedures WHERE procedure_number = '01-02' LIMIT 1)
);
